// Package device brings a wanbond tunnel up from a validated configuration: it
// creates the TUN interface, drives the embedded amneziawg-go engine over the
// multipath Bind, and applies the WireGuard (and, when configured, amnezia
// obfuscation) parameters via the engine's UAPI. It owns ONLY the tunnel engine
// — interface addressing and routing are left to the operator (systemd/wg-quick
// style), so the daemon stays free of privileged shell-outs. The interface name
// is exposed via Tunnel.Name for that external configuration step.
package device

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"errors"
	"fmt"
	"net/netip"
	"reflect"
	"strings"
	"sync"
	"sync/atomic"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"
	"github.com/amnezia-vpn/amneziawg-go/tun"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/bind"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/dnsresolve"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/metrics"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// metricsShutdownTimeout bounds the graceful shutdown of the /metrics endpoint on
// Close (and on a reload that rebinds it). The endpoint is loopback-only with no
// long-lived scrapes, so this is comfortably generous.
const metricsShutdownTimeout = 2 * time.Second

// defaultTUNName is the requested interface name; the kernel honours it unless it
// collides (it never does across the edge and concentrator network namespaces).
const defaultTUNName = "wanbond0"

// tunMTU is the tunnel (TUN) MTU for a config: the default path MTU minus the
// IP+UDP, outer DATA-frame, and WireGuard transport overheads, so a full-MTU inner
// packet never fragments on the wire (see internal/bind mtu.go and docs/p1-mtu.md).
// This is smaller than the plain-WireGuard 1420 because the bonding layer adds its
// own outer DATA frame per datagram; with FEC enabled it is a further
// bind.FECParityMTUPenalty smaller so a full-size PARITY frame also fits the path MTU
// (T24) rather than fragmenting.
func tunMTU(cfg *config.Config) int {
	return bind.InnerMTU(bind.DefaultPathMTU, cfg.FEC.Enabled)
}

// Tunnel is a running wanbond tunnel: the amneziawg engine, its TUN, and the
// multipath Bind. Close tears all three down.
type Tunnel struct {
	dev  *awgdevice.Device
	tun  tun.Device
	name string
	// routePrefixes is the default-route wiring installed into wanbond0 for a
	// mode=default-route peer (I6, Q41): the wg-quick-style split of that peer's
	// allowed_ips (the two /1s for a /0), installed after dev.Up and withdrawn on
	// Close. Empty (nil) for a config with no default-route peer, so a plain tunnel
	// programs — and tears down — no routes at all.
	routePrefixes []netip.Prefix
	// bind is the multipath Bind the engine drives; Reload calls its runtime
	// AddPath/RemovePath to apply a config-reload path diff (T30).
	bind *bind.Multipath
	// cfg is the configuration the RUNNING tunnel reflects: the boot config, its path
	// set updated on each successful Reload to the current membership (survivors keep
	// their original parameters — a membership-only reload does not re-apply modified
	// path parameters or non-path fields). Reload diffs the next desired config against
	// it to warn about changes it cannot apply. Guarded by reloadMu.
	cfg *config.Config
	// reloadMu serializes Reload against itself (SIGHUP handlers), guarding cfg.
	reloadMu sync.Mutex
	// log is the device-component logger, retained for Reload diagnostics.
	log log.Logger
	// stopProbes halts the per-path probe cadence loop (T37). Close calls it before
	// tearing the engine down so emission stops before the sockets close. It is
	// idempotent and never nil (a no-op when the bind runs without probers).
	stopProbes func()
	// stopReconcile halts the background deferred-path reconcile loop (T55): it retries
	// binding the paths a tolerant Open left DOWN as their addresses appear. Close calls
	// it before tearing the engine down so no reconcile races the socket close. It is
	// idempotent and never nil (a no-op when the bind runs without probers / never defers).
	stopReconcile func()
	// stopHubFailover halts the edge-side hub-failover monitor loop (T57): it watches the
	// per-path liveness plane and, on hub loss (all paths to the active concentrator DOWN),
	// advances to the next ordered peer endpoint, repoints the bond's remote, and initiates
	// a fresh WG re-handshake. Close calls it before tearing the engine down. It is
	// idempotent and never nil (a no-op on the concentrator, or an edge with a single
	// concentrator endpoint, or a bind without the probe transport).
	stopHubFailover func()
	// stopResolution halts the edge-side DNS re-resolution loop (T74): it re-resolves each
	// opted-in hostname peer-endpoint spec on the [dns] poll cadence and out-of-band on hub loss,
	// feeding fresh records to the hub-failover controller. Close calls it between stopHubFailover
	// and dev.Close. It is idempotent and never nil (a no-op on the concentrator, an all-literal
	// edge, or when no hostname spec is configured — Q29 inertness).
	stopResolution func()
	// stopSession halts the WG-session monitor loop (I2): it polls the engine's last-handshake
	// state at probe cadence and emits ONE INFO 'session established' record on each 0->1 edge.
	// Close calls it before dev.Close so no IpcGet races the engine teardown. It is idempotent
	// and never nil.
	stopSession func()
	// amnezia is the obfuscation profile this tunnel holds against the
	// process-global amnezia guard (see amneziaGuard); Close releases it.
	amnezia     config.Amnezia
	releaseOnce sync.Once

	// metricsSrc is the live metrics.Source over the Bind; it is stable for the tunnel's
	// life (the Bind pointer never changes), so a reload that rebinds the endpoint reuses
	// the SAME Source — its derived-throughput last-sample state survives the rebind.
	metricsSrc metrics.Source
	// metricsSrv is the running /metrics endpoint, nil when [metrics].listen is empty.
	// It is (re)assigned by applyMetricsLocked and read by Close; both hold reloadMu, so
	// a SIGHUP-driven rebind never races shutdown. metricsListen mirrors the address it
	// is bound to so a reload can detect a listen change without inspecting the server.
	metricsSrv    *metrics.Server
	metricsListen string
}

// SINGLE-ENGINE-PER-PROCESS INVARIANT (defect D2).
//
// amneziawg-go stores the amnezia magic-header message types in PACKAGE-GLOBAL
// variables — device.MessageInitiationType, MessageResponseType,
// MessageCookieReplyType, MessageTransportType. (*device.Device).IpcSet assigns
// them (in handlePostConfig) from a configured engine's profile, and
// (*device.Device).Close restores them to the WireGuard defaults (in
// resetProtocol) UNCONDITIONALLY — closing ANY engine, plain or configured,
// reverts the process-global message types to their defaults.
//
// Two consequences make a CONFIGURED (amnezia) engine require PROCESS
// EXCLUSIVITY:
//   - a second configured engine would overwrite the first engine's message-type
//     framing at IpcSet; and even with the SAME profile, closing the first engine
//     runs resetProtocol and reverts the globals to defaults under the second,
//     still-live engine, silently dropping its tunnel to plain-WireGuard framing.
//   - closing ANY other engine — a PLAIN (unconfigured) one included — runs
//     resetProtocol and resets the globals out from under a live configured engine.
//
// So the rule wanbond ASSERTS (rather than vendor-patching the fork) is:
//   - a configured engine may come up only when NO other engine is live, and
//   - no engine (plain or configured) may come up while a configured engine is live.
//
// PLAIN engines may coexist with each other: they never set the globals, and
// resetProtocol on their Close only restores the defaults they already use, so it
// is idempotent among them. wanbond runs exactly one tunnel per process, so the
// guard only ever trips on genuine misuse.
type amneziaGuard struct {
	mu         sync.Mutex
	plainLive  int  // number of live plain-WireGuard (unconfigured) engines
	configLive bool // whether a configured (amnezia) engine is live (at most one)
}

// globalAmneziaGuard enforces the single-amnezia-engine-per-process invariant for
// every Tunnel brought up in this process.
var globalAmneziaGuard amneziaGuard

// acquire registers an about-to-start engine against the process-exclusivity rule
// (see amneziaGuard). A configured (amnezia) engine is admitted only when NO other
// engine is live. A plain engine is admitted only when no configured engine is
// live; plain engines may coexist with one another. The caller must release the
// SAME profile exactly once when the engine is torn down (plain engines included —
// release is no longer a no-op for them).
func (g *amneziaGuard) acquire(a config.Amnezia) error {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		if g.configLive || g.plainLive > 0 {
			return fmt.Errorf("device: refusing to start an amnezia-configured engine while another engine is live: " +
				"amneziawg-go keeps the magic-header message types in process-global state and resets them to defaults on ANY engine's Close, " +
				"so a configured engine requires process exclusivity — at most one, with no other engine alongside it (D2)")
		}
		g.configLive = true
		return nil
	}
	if g.configLive {
		return fmt.Errorf("device: refusing to start a second engine while an amnezia-configured engine is live: " +
			"closing this engine would reset amneziawg-go's process-global message types to defaults under the live amnezia tunnel (D2)")
	}
	g.plainLive++
	return nil
}

// release drops an engine's hold on the guard. A configured engine clears the
// single configured slot; a plain engine decrements the live plain count.
func (g *amneziaGuard) release(a config.Amnezia) {
	g.mu.Lock()
	defer g.mu.Unlock()
	if a.Configured() {
		g.configLive = false
		return
	}
	if g.plainLive > 0 {
		g.plainLive--
	}
}

// Up creates the TUN, wires the multipath Bind into the amneziawg engine,
// applies the crypto configuration from cfg, and brings the device up. The same
// path drives both roles; the role only changes which UAPI fields cfg carries
// (the concentrator sets listen_port; the edge sets each peer's endpoint).
func Up(cfg *config.Config, lg log.Logger) (*Tunnel, error) {
	clg := lg.Component("device")

	tunDev, err := tun.CreateTUN(defaultTUNName, tunMTU(cfg))
	if err != nil {
		return nil, fmt.Errorf("device: create TUN: %w", err)
	}
	name, err := tunDev.Name()
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: read TUN name: %w", err)
	}
	// Bring the interface administratively UP now (I1): amneziawg-go never does this
	// itself, and a write to a DOWN TUN yields EIO — a silent-dead-tunnel footgun the
	// operator previously had to work around with an out-of-band `ip link set up`.
	// Addressing stays operator-owned; this sets ONLY the IFF_UP flag (see ifUp).
	if err := ifUp(name); err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: bring interface up: %w", err)
	}
	// Apply the TUN persistence policy (I7, Q38) BEFORE the amnezia single-engine
	// guard in up(): with tun_persist=true the kernel keeps wanbond0 (and its
	// operator-owned addresses/routes) across a daemon restart; with the default
	// false it explicitly CLEARS the flag so the device disappears on Close exactly
	// as before. This composes with the ifUp above and does not touch the reload or
	// restart-on-failure paths — a reload never re-creates the TUN, and a persistent
	// device is simply re-adopted by name on the next Up (see setTUNPersist).
	if err := setTUNPersist(tunDev, cfg.TUNPersist); err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: set TUN persistence: %w", err)
	}
	clg.Info("interface up", "interface", name, "tun_persist", cfg.TUNPersist)
	// The DNS re-resolution transport is the one the (validated) [dns] block selects. It is passed
	// as a factory (not eagerly constructed) so up() builds it AT MOST ONCE and ONLY when some peer
	// carries a hostname endpoint spec — a config with zero hostname specs never constructs a
	// resolver (Q29 inertness). The injected TUN and factory are also the seams device tests drive.
	return up(cfg, clg, tunDev, name, cfg.DNS.NewResolver)
}

// resolverFactory builds the DNS resolver used for hostname endpoint re-resolution. It is injected
// so a device test can supply a fake; production passes cfg.DNS.NewResolver. up() invokes it AT
// MOST ONCE, and ONLY when some peer carries a hostname endpoint spec.
type resolverFactory func() (dnsresolve.Resolver, error)

// up drives the tunnel bring-up over an already-created TUN and an injected resolver factory: it
// wires the multipath Bind into the amneziawg engine, performs the bounded initial hostname
// resolve (Q30), applies the crypto/endpoint UAPI config built ONLY from resolved entries, brings
// the device up, and starts the probe / reconcile / hub-failover / re-resolution loops. Splitting
// it out of Up gives device tests a seam to inject a channel TUN and a fake resolver without the
// privileged tun.CreateTUN. The same path drives both roles; the role only changes which UAPI
// fields cfg carries (the concentrator sets listen_port; the edge sets each peer's endpoint).
func up(cfg *config.Config, clg log.Logger, tunDev tun.Device, name string, newResolver resolverFactory) (*Tunnel, error) {
	// Wrap the TUN so a write that fails with EIO gets an actionable, rate-limited diagnostic
	// (naming the interface's link state/MTU and the remedy) alongside the raw errno, instead
	// of surfacing only as the engine's generic "input/output error" (D39, I3). Every other
	// Device method is unaffected.
	tunDev = newDiagnosingTUN(tunDev, name, clg)

	// Claim the single-amnezia-engine-per-process invariant (D2) BEFORE IpcSet
	// assigns amneziawg-go's process-global message-type state. On any failure
	// below, ok stays false and the deferred release returns the hold; the
	// successful path transfers the hold to the returned Tunnel.
	if err := globalAmneziaGuard.acquire(cfg.Amnezia); err != nil {
		_ = tunDev.Close()
		return nil, err
	}
	ok := false
	defer func() {
		if !ok {
			globalAmneziaGuard.release(cfg.Amnezia)
		}
	}()

	// One random per-boot probe session id, shared by every path AND every configured peer (it
	// identifies THIS boot, not a path or peer): a peer restart presents a new id that resets
	// the surviving responder's anti-replay high-water so liveness recovers (T38, D12), and a
	// runtime-added path (T30) reuses it so its probes join this boot's stream.
	sessionID, err := telemetry.NewSessionID(rand.Reader)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: new probe session id: %w", err)
	}
	// PeerIdentities is the SINGLE place the single-peer/multi-peer effective-PSK decision is
	// made (G4): for a single-peer config every identity's PSK is the top-level psk; for a
	// multi-peer concentrator each is that peer's own psk. Its order matches cfg.WireGuard.Peers
	// (and thus uapiConfig's peer render), so the engine peer set and the Bind peer set agree.
	ids := cfg.PeerIdentities()
	// The primary peer (peers[0]) drives on-wire liveness through the SAME prober values that
	// back its scheduler's PathHealth (T37). It is keyed on the FIRST identity's effective psk:
	// the top-level psk for a single-peer config (byte-identical to pre-G4), or peer 0's own psk
	// for a multi-peer concentrator.
	scheduler, probers, newProber, err := buildScheduler(cfg, ids[0].PSK, sessionID, clg)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build scheduler: %w", err)
	}
	mpBind, err := bind.NewMultipath(cfg.Paths, ids[0].PSK, scheduler, probers, newProber, fecConfig(cfg.FEC), adaptiveFECConfig(cfg.FEC), cfg.Amnezia)
	if err != nil {
		_ = tunDev.Close()
		return nil, fmt.Errorf("device: build multipath bind: %w", err)
	}
	// Concentrator per-peer wiring (G4/T93): register each ADDITIONAL configured peer with its
	// OWN prober set, scheduler, and prober factory (all keyed on that peer's effective psk),
	// BEFORE dev.Up drives the bind's Open — which builds each registered peer's per-(peer,path)
	// view of every bound socket, reconciles its scheduler, and reports its stable virtual
	// endpoint to the engine (A1). A single-peer config has exactly one identity, so this loop
	// is empty and the wiring stays byte-identical to the pre-G4 single-peer path.
	for _, id := range ids[1:] {
		psched, pprobers, pfactory, perr := buildScheduler(cfg, id.PSK, sessionID, clg)
		if perr != nil {
			_ = tunDev.Close()
			return nil, fmt.Errorf("device: build scheduler for peer %q: %w", id.Name, perr)
		}
		if perr := mpBind.AddConcentratorPeer(id.Name, id.PSK, psched, pprobers, pfactory); perr != nil {
			_ = tunDev.Close()
			return nil, fmt.Errorf("device: wire concentrator peer %q: %w", id.Name, perr)
		}
	}
	dev := awgdevice.NewDevice(tunDev, mpBind, engineLogger(clg, cfg.Log.Level, mpBind.EverHadLivePath))

	// Bounded initial hostname resolution (Q30): construct the resolver ONCE (only when some peer
	// carries a hostname spec — Q29 inertness), resolve each hostname spec under a short timeout,
	// and seed its expansion. The per-peer boot endpoint — the flattened head of the seeded specs —
	// is what the UAPI render installs on the engine peer; a hostname that does not resolve in the
	// boot window (or a resolver that fails to construct) leaves its spec EMPTY and the peer boots
	// WITHOUT a peer endpoint (tolerant boot). The re-resolution loop then completes the wiring on
	// first success via the FIRST-RESOLVE INSTALL PATH (R70). Literal specs are seeded verbatim, so
	// an all-literal peer boots byte-for-byte as before.
	boot := resolveBootEndpoints(cfg, newResolver, clg)

	uapi, err := uapiConfig(cfg, boot.endpoints)
	if err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: build UAPI config: %w", err)
	}
	if err := dev.IpcSet(uapi); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: apply UAPI config: %w", err)
	}
	if err := dev.Up(); err != nil {
		dev.Close()
		return nil, fmt.Errorf("device: bring up: %w", err)
	}

	// Default-route wiring (I6, Q41): with a mode=default-route peer, install the
	// wg-quick-style split default route (the two /1s of that peer's allowed_ips) INTO
	// wanbond0 now that the interface is up and the engine is running, so an arbitrary
	// destination egresses through the tunnel. This is the daemon's FIRST route
	// programming — confined to the mode being explicitly enabled: a config with no
	// default-route peer computes an empty set, opens no netlink socket, and installs
	// nothing, so default behaviour is byte-for-byte unchanged. STRICT Q41 boundary —
	// routes ONLY (no policy routing, no SNAT, no concentrator forwarding). Fail fast:
	// a route error aborts bring-up. Before returning we best-effort withdraw whatever
	// partial set installRoutes landed: dev.Close tears down the engine/TUN, but under
	// tun_persist=true the interface (and its routes) SURVIVES Close, and up() aborts
	// before the Tunnel exists so Close/removeRoutes never runs — the already-installed
	// prefixes would otherwise leak on the surviving interface. removeRoutes errors are
	// ignored (the install error is the one that matters; a leftover is overwritten by
	// the next successful start's NLM_F_REPLACE re-install anyway). Removed on Close.
	routePrefixes := defaultRoutePrefixes(cfg)
	if len(routePrefixes) > 0 {
		if err := installRoutes(name, routePrefixes); err != nil {
			_ = removeRoutes(name, routePrefixes)
			dev.Close()
			return nil, fmt.Errorf("device: install default-route wiring: %w", err)
		}
		clg.Info("default-route wiring installed", "interface", name, "routes", len(routePrefixes))
	}

	// The engine has opened the bind (dev.Up → BindUpdate → Open), so the per-path
	// sockets exist: start the probe cadence now. Close stops it before dev.Close.
	// The interval is the SINGLE-SOURCE-OF-TRUTH telemetry default, which also arms
	// the bind's receive-path liveness sweep throttle (D15).
	stopProbes := mpBind.StartProbeLoop(telemetry.DefaultProbeInterval)
	// Start the background deferred-path reconciler alongside probing (T55): a path the
	// tolerant Open left DOWN (its source_addr not yet assignable — a 5G modem without a
	// lease at boot) is retried and promoted to a live path as its address appears,
	// WITHOUT a tunnel restart. Close stops it before dev.Close, like the probe loop.
	stopReconcile := mpBind.StartReconcileLoop(bind.DefaultReconcileInterval)
	// Start the edge-side hub-failover monitor (T57) AND the DNS re-resolution loop (T74): on hub
	// loss (every path to the active concentrator DOWN) failover advances to the next ordered peer
	// endpoint, repoints the bond's remote, and re-handshakes; re-resolution re-resolves opted-in
	// hostname specs and installs/repoints on change. Both a no-op on the concentrator, a
	// single-IP-literal edge, or a bind without the probe transport. Started AFTER dev.Up so the
	// engine peer the re-handshake / endpoint-install look up exists (IpcSet added it above). Close
	// stops both before dev.Close, like the probe/reconcile loops.
	stopHubFailover, stopResolution := startFailoverAndResolution(cfg, mpBind, probers, dev, boot, clg)

	// The session monitor reads the engine's peer last-handshake state (I2). It backs BOTH
	// the /metrics session snapshot (read at scrape time) and the 0->1 'session established'
	// edge log (driven by its own poll loop). One instance is shared: it is stateless, so the
	// concurrent scrape goroutine and the poll loop reading the same engine is safe.
	sessMon := newSessionMonitor(dev, telemetry.SystemClock{})
	// Start the WG-session monitor poll loop AFTER dev.Up so the engine peer it reads exists.
	// Close stops it before dev.Close, like the probe/reconcile loops.
	stopSession := startSessionMonitor(sessMon, sessionPollInterval, clg)

	t := &Tunnel{
		dev: dev, tun: tunDev, name: name, bind: mpBind, cfg: cfg, log: clg,
		routePrefixes: routePrefixes,
		stopProbes:    stopProbes, stopReconcile: stopReconcile,
		stopHubFailover: stopHubFailover, stopResolution: stopResolution,
		stopSession: stopSession, amnezia: cfg.Amnezia,
		// The Source reads live per-path counters/telemetry from the Bind and derives
		// throughput from the byte-counter delta between scrapes (see metricsSource). The
		// WG-session snapshot is read from the engine via sessMon. It is built unconditionally
		// (cheap) so a reload that later turns [metrics].listen ON has a Source ready; the
		// endpoint itself is started only when a listen is configured.
		metricsSrc: newMetricsSource(mpBind, sessMon, telemetry.SystemClock{}),
	}

	// Stand up the /metrics endpoint when configured. A non-loopback listen is refused
	// by metrics.NewServer (fail fast) — surface it as an Up failure rather than booting
	// a tunnel that silently exposes per-path operational data off-host.
	t.reloadMu.Lock()
	err = t.applyMetricsLocked(cfg.Metrics.Listen)
	t.reloadMu.Unlock()
	if err != nil {
		// The tunnel is fully constructed and holds the amnezia guard, so transfer that
		// ownership to it (ok=true) BEFORE tearing it down: t.Close releases the guard via
		// releaseOnce, and suppressing the !ok defer avoids a double release. t.Close also
		// stops the probe loop and closes the engine/TUN.
		ok = true
		t.Close()
		return nil, fmt.Errorf("device: start metrics endpoint: %w", err)
	}

	ok = true
	clg.Info("tunnel up", "interface", name, "role", string(cfg.Role))
	return t, nil
}

// applyMetricsLocked reconciles the running /metrics endpoint to listen: it starts the
// endpoint when one is desired and none runs, stops it when listen is empty, and rebinds
// (stop old, start new) when the address changed. It is idempotent for an unchanged
// address. The Source is reused across a rebind so its derived-throughput state is not
// reset. The caller MUST hold reloadMu (Up and Reload both do), which also serializes it
// against Close reading metricsSrv. On a NewServer/refuse error the previous server is
// left running untouched, so a bad reload never drops a working endpoint.
func (t *Tunnel) applyMetricsLocked(listen string) error {
	if listen == t.metricsListen {
		return nil
	}
	if listen == "" {
		t.stopMetricsLocked()
		return nil
	}
	srv, err := metrics.NewServer(listen, t.metricsSrc, t.log)
	if err != nil {
		return err
	}
	t.stopMetricsLocked()
	srv.Start()
	t.metricsSrv = srv
	t.metricsListen = listen
	return nil
}

// stopMetricsLocked gracefully shuts the running endpoint down (if any) and clears the
// bookkeeping. Caller holds reloadMu.
func (t *Tunnel) stopMetricsLocked() {
	if t.metricsSrv == nil {
		return
	}
	ctx, cancel := context.WithTimeout(context.Background(), metricsShutdownTimeout)
	defer cancel()
	if err := t.metricsSrv.Close(ctx); err != nil {
		t.log.Warn("metrics endpoint shutdown error", "error", err.Error())
	}
	t.metricsSrv = nil
	t.metricsListen = ""
}

// Reload applies a reloaded configuration to the RUNNING tunnel by diffing its
// path set against the live one and adding/removing paths at runtime (T30), WITHOUT
// tearing the tunnel down: the WG session, the surviving paths, and in-flight
// resequencing are all preserved. cfg is assumed already validated (config.Load
// fails fast on a bad file, so a bad reload never reaches here and never disturbs
// the running tunnel). Only the path set is diffed — the crypto/amnezia/role fields
// are fixed for the life of the process and a reload does not re-key the engine.
//
// New paths are added BEFORE absent ones are removed, so a failed addition aborts
// with every existing path still in service. Diffing is by name: a path present in
// both sets is left untouched (its source/dest parameters are not re-read).
//
// A membership-only reload CANNOT apply every kind of change: a same-name path whose
// source/dest changed, a path REORDER (index 0 is the preferred primary, so a reorder
// is a priority change), and every non-path field (psk, wireguard, amnezia, role, log,
// metrics) are all out of scope for T30. Rather than silently diverge from the file,
// Reload logs an EXPLICIT WARNING per ignored change (reloadWarnings) so the operator
// knows exactly what was dropped; only the path-membership add/remove is applied.
func (t *Tunnel) Reload(cfg *config.Config) error {
	t.reloadMu.Lock()
	defer t.reloadMu.Unlock()

	for _, w := range reloadWarnings(t.cfg, cfg) {
		t.log.Warn("reload: ignored config change (path-membership reload only)", "change", w)
	}

	// Rebind the /metrics endpoint if its listen address changed (T23). This is one of
	// the few non-path fields a reload DOES apply: the endpoint is external to the WG
	// session and the Bind, so restarting it disturbs neither. applyMetricsLocked reuses
	// the tunnel's stable Source (its derived-throughput state survives), and on a refuse
	// (e.g. a newly non-loopback address) leaves the previous endpoint running and fails
	// the reload — the running tunnel is never disturbed. Applied BEFORE the path diff so
	// a metrics-refuse aborts before any membership change.
	if cfg.Metrics.Listen != t.metricsListen {
		if err := t.applyMetricsLocked(cfg.Metrics.Listen); err != nil {
			return fmt.Errorf("device: reload metrics endpoint: %w", err)
		}
		t.log.Info("reload: metrics endpoint rebound", "listen", cfg.Metrics.Listen)
	}

	add, remove := diffPaths(t.bind.PathNames(), cfg.Paths)
	for _, def := range add {
		if err := t.bind.AddPath(def); err != nil {
			return fmt.Errorf("device: reload add path %q: %w", def.Name, err)
		}
		t.log.Info("reload: path added", "path", def.Name)
	}
	for _, name := range remove {
		if err := t.bind.RemovePath(name); err != nil {
			return fmt.Errorf("device: reload remove path %q: %w", name, err)
		}
		t.log.Info("reload: path removed", "path", name)
	}
	// Advance the running config to the membership now in service. Survivors keep their
	// ORIGINAL parameters and all non-path fields stay as booted (the ignored changes
	// were not applied), so a subsequent identical reload re-warns about a still-diverged
	// file rather than silently accepting it. Metrics.Listen is carried to the applied
	// value so a subsequent reload diffs against the endpoint actually running.
	t.cfg = runningConfig(t.cfg, add, remove)
	t.cfg.Metrics.Listen = t.metricsListen
	return nil
}

// reloadWarnings compares the desired config against the currently-running one and
// returns one human-readable warning per change a path-membership-only reload (T30)
// cannot apply: a modified same-name path (source/dest), a path reorder, and any
// non-path field. Membership add/remove is NOT reported here — it is applied. Full
// modify-support is out of scope; SILENCE is not — the operator must be told what was
// ignored. It is a pure function so the warning set is unit-testable.
func reloadWarnings(live, desired *config.Config) []string {
	var w []string

	if live.Role != desired.Role {
		w = append(w, fmt.Sprintf("role %q -> %q", live.Role, desired.Role))
	}
	if !reflect.DeepEqual(live.PSK, desired.PSK) {
		w = append(w, "psk changed")
	}
	if !reflect.DeepEqual(live.WireGuard, desired.WireGuard) {
		w = append(w, "wireguard section changed")
	}
	if !reflect.DeepEqual(live.Amnezia, desired.Amnezia) {
		w = append(w, "amnezia section changed")
	}
	if !reflect.DeepEqual(live.Log, desired.Log) {
		w = append(w, "log section changed")
	}
	// tun_persist is applied only once, at device.Up (TUNSETPERSIST); a reload never
	// re-issues the ioctl, so a SIGHUP that flips it must NOT be silently accepted —
	// otherwise an operator who sets tun_persist=true and reloads believes persistence
	// is armed while the next stop still destroys wanbond0 and drops its addressing.
	if live.TUNPersist != desired.TUNPersist {
		w = append(w, fmt.Sprintf("tun_persist %v -> %v — the running interface keeps its original persistence; ignored until restart", live.TUNPersist, desired.TUNPersist))
	}
	// NOTE: a Metrics change is NOT warned here — unlike the other non-path fields, the
	// reload APPLIES it by rebinding the /metrics endpoint (see Reload). Warning about a
	// change that is honoured would misinform the operator.

	// Same-name paths whose parameters changed: diffPaths matches by name only, so a
	// modified source/dest on an existing path is otherwise silently dropped.
	liveByName := make(map[string]config.Path, len(live.Paths))
	for _, p := range live.Paths {
		liveByName[p.Name] = p
	}
	for _, d := range desired.Paths {
		l, ok := liveByName[d.Name]
		if !ok {
			continue // a genuinely new path is added, not ignored
		}
		if l.SourceAddr != d.SourceAddr || l.DestAddr != d.DestAddr {
			w = append(w, fmt.Sprintf("path %q source/dest changed — the running path keeps its original binding", d.Name))
		}
	}

	if reordered(live.Paths, desired.Paths) {
		w = append(w, "path priority order changed (reorder) — the running order is unchanged")
	}
	return w
}

// reordered reports whether the paths common to BOTH slices appear in a different
// relative order in desired than in live. The common subsequence has the same length
// on both sides (it is the name intersection), so a positional mismatch is a reorder.
func reordered(live, desired []config.Path) bool {
	desiredNames := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredNames[p.Name] = struct{}{}
	}
	liveNames := make(map[string]struct{}, len(live))
	for _, p := range live {
		liveNames[p.Name] = struct{}{}
	}
	var liveCommon, desiredCommon []string
	for _, p := range live {
		if _, ok := desiredNames[p.Name]; ok {
			liveCommon = append(liveCommon, p.Name)
		}
	}
	for _, p := range desired {
		if _, ok := liveNames[p.Name]; ok {
			desiredCommon = append(desiredCommon, p.Name)
		}
	}
	for i := range liveCommon {
		if liveCommon[i] != desiredCommon[i] {
			return true
		}
	}
	return false
}

// runningConfig advances the running config to the membership the bind now serves:
// the survivors (live paths not removed, keeping their ORIGINAL parameters and order)
// followed by the added paths (their new parameters). Non-path fields are carried over
// unchanged — a membership-only reload does not re-apply them. It mirrors the m.defs
// order the bind rebuilds on a Close→Open (survivors-in-order, then appended adds).
func runningConfig(live *config.Config, add []config.Path, remove []string) *config.Config {
	removeSet := make(map[string]struct{}, len(remove))
	for _, n := range remove {
		removeSet[n] = struct{}{}
	}
	paths := make([]config.Path, 0, len(live.Paths)+len(add))
	for _, p := range live.Paths {
		if _, gone := removeSet[p.Name]; !gone {
			paths = append(paths, p)
		}
	}
	paths = append(paths, add...)
	running := *live
	running.Paths = paths
	return &running
}

// diffPaths computes, by name, which desired paths are not yet live (to add) and
// which live paths are no longer desired (to remove). It is a pure function so the
// reload diff is unit-testable without a running engine.
func diffPaths(live []string, desired []config.Path) (add []config.Path, remove []string) {
	liveSet := make(map[string]struct{}, len(live))
	for _, n := range live {
		liveSet[n] = struct{}{}
	}
	desiredSet := make(map[string]struct{}, len(desired))
	for _, p := range desired {
		desiredSet[p.Name] = struct{}{}
		if _, ok := liveSet[p.Name]; !ok {
			add = append(add, p)
		}
	}
	for _, n := range live {
		if _, ok := desiredSet[n]; !ok {
			remove = append(remove, n)
		}
	}
	return add, remove
}

// defaultFailbackDwell is how long a recovered higher-priority path must stay up
// before egress fails BACK to it, damping flap-induced thrash (T15 hysteresis).
// Unlike the probe-cadence/liveness thresholds (which are the shared
// telemetry.Default* single source of truth, D16), the failback dwell is not part
// of the failover-recovery budget — failover to a backup is instant — so it stays a
// device-local constant.
const defaultFailbackDwell = 5 * time.Second

// fecConfig maps the validated [fec] config block onto the fec.Config the multipath
// Bind consumes (T24), or returns nil when FEC is disabled so the Bind runs the
// datapath with no parity plane. The ratio was already range-checked in config
// validation; the Bind re-validates defensively.
func fecConfig(f config.FEC) *fec.Config {
	if !f.Enabled {
		return nil
	}
	return &fec.Config{
		DataShards:   f.DataShards,
		ParityShards: f.ParityShards,
		Deadline:     f.Deadline,
	}
}

// adaptiveFECConfig maps the [fec] block onto the adaptive controller config the multipath
// Bind drives (T29), or returns nil when FEC is disabled or the block did not opt into
// adaptive mode — in which case the Bind runs the fixed-ratio plane (T24) unchanged. The
// controller uses the simulation-proven default control law (internal/adaptivefec,
// DefaultConfig), with only the group geometry pinned to the configured ratio: DataShards
// (K) is the FEC data_shards and MaxParity (the parity CEILING) is the FEC parity_shards,
// which the receiver's decoder is built at. The Bind re-validates and cross-checks these
// against the FEC config defensively.
func adaptiveFECConfig(f config.FEC) *adaptivefec.Config {
	if !f.Enabled || !f.Adaptive {
		return nil
	}
	c := adaptivefec.DefaultConfig()
	c.DataShards = f.DataShards
	c.MaxParity = f.ParityShards
	// Exactly one sizing mode is active (config load enforces mutual exclusion): in the
	// residual-SLA mode f.SafetyFactor is 0 and f.TargetResidual drives M; in the legacy
	// mode f.TargetResidual is 0 and f.SafetyFactor (defaulted at load) drives M.
	c.SafetyFactor = f.SafetyFactor
	c.TargetResidual = f.TargetResidual
	return &c
}

// buildScheduler constructs ONE peer's boot-time per-path prober set, its runtime prober
// factory, and the send scheduler over them — ALL keyed on that peer's effective psk (R72) —
// in cfg.Paths' configured priority order (index 0 = the preferred primary path). The returned
// probers ARE the scheduler's PathHealth sources (a *Prober is internally synchronized,
// satisfying the PathHealth concurrency contract — a bare *Liveness would not) and are handed
// to the bind so the probe transport drives the very same liveness the scheduler selects on
// (T37 replaces the T15 sched.AlwaysUp placeholder with real on-wire failover).
//
// The single-peer edge/hub/concentrator calls this once (psk = the top-level effective psk, so
// the wiring is byte-identical to pre-G4); a multi-peer concentrator calls it once per
// configured peer, each with that peer's OWN effective psk, so one peer's probers/reflector
// authenticate under a DIFFERENT key and reject another peer's frames (T84). sessionID is the
// per-boot probe session id — it identifies THIS boot, not a path or peer — shared by every
// path AND every peer: each peer's reflector keys anti-replay under its own psk, so a shared
// session id never conflates two peers' probe streams, and a runtime-added path (T30) reuses it
// so its probes join this boot's stream and the peer's reflector adopts them without a
// challenge reset.
func buildScheduler(cfg *config.Config, psk config.Key, sessionID uint64, lg log.Logger) (sched.Scheduler, []*telemetry.Prober, bind.ProberFactory, error) {
	clock := telemetry.SystemClock{}
	proberCfg := telemetry.ProberConfig{
		LossWindow: telemetry.DefaultLossWindow,
		Liveness: telemetry.LivenessConfig{
			DownAfter:        telemetry.DefaultDownAfter,
			UpAfterSuccesses: telemetry.DefaultUpSuccesses,
		},
	}
	// newProber mints one path's Prober with the shared session/config/clock, keyed on THIS
	// peer's psk. It is the single construction point for this peer's boot-time AND runtime
	// paths, so both measure liveness identically.
	newProber := func(name string, id uint8) *telemetry.Prober {
		return telemetry.NewProber(name, id, sessionID, psk, proberCfg, clock, lg)
	}
	probers := make([]*telemetry.Prober, len(cfg.Paths))
	health := make([]sched.PathHealth, len(cfg.Paths))
	quality := make([]sched.PathQuality, len(cfg.Paths))
	for i := range cfg.Paths {
		probers[i] = newProber(cfg.Paths[i].Name, uint8(i))
		health[i] = probers[i]
		quality[i] = probers[i]
	}
	// Policy is a config choice: active-backup (P1, default) or the T21 weighted-
	// aggregation policy. Both consume the SAME per-path *Prober set — a *Prober
	// satisfies BOTH PathHealth (liveness) and PathQuality (RTT/loss Estimate) — so the
	// probe transport drives the very liveness/quality the scheduler selects on, and the
	// swap is behind config with no Bind change.
	scheduler, err := selectScheduler(cfg, health, quality, clock, lg)
	if err != nil {
		return nil, nil, nil, err
	}
	return scheduler, probers, newProber, nil
}

// selectScheduler builds the send scheduler the configured policy names, over the
// per-path health (and, for the weighted policy, quality) sources. active-backup is
// the P1 default; weighted is T21. The weighted knobs are validated at config load,
// so translating them here cannot fail on range — only NewWeighted's structural
// checks (which the wiring satisfies) apply.
func selectScheduler(cfg *config.Config, health []sched.PathHealth, quality []sched.PathQuality, clock telemetry.Clock, lg log.Logger) (sched.Scheduler, error) {
	switch cfg.Scheduler.Policy {
	case config.PolicyWeighted:
		sc := cfg.Scheduler
		return sched.NewWeighted(health, quality, sched.WeightedConfig{
			PerPathCapacity:   sc.PerPathCapacityFPS,
			EngageFraction:    sc.EngageFraction,
			DisengageFraction: sc.DisengageFraction,
			CollapseDwell:     sc.CollapseDwell,
			LoadTau:           sc.LoadTau,
			Pacing:            sc.PacingEnabled,
			PacingBurst:       sc.PacingBurstFrames,
			WeightRTTFloor:    sc.WeightRTTFloor,
			WeightLossFloor:   sc.WeightLossFloor,
		}, clock, lg)
	default:
		// active-backup (and the empty default, normalized to it at config load).
		return sched.NewActiveBackup(
			health,
			sched.Config{FailbackAfter: defaultFailbackDwell},
			clock,
			lg,
		)
	}
}

// Name is the created TUN interface name (for external addressing/routing).
func (t *Tunnel) Name() string { return t.name }

// Wait blocks until the device is torn down (its own Close, or an unrecoverable
// engine error).
func (t *Tunnel) Wait() { <-t.dev.Wait() }

// Close stops the probe loop, brings the device down, and releases the TUN and
// Bind. Idempotent. It also releases this tunnel's hold on the single-amnezia-
// engine-per-process guard exactly once, so a later Up may reconfigure the
// process-global amnezia state. Probing is stopped BEFORE the engine tears the
// bind's sockets down so no emission races the close.
func (t *Tunnel) Close() {
	// Shut the scrape endpoint FIRST so no in-flight /metrics scrape reads the Bind while
	// the engine tears its sockets down. reloadMu serializes this against a concurrent
	// SIGHUP-driven rebind.
	t.reloadMu.Lock()
	t.stopMetricsLocked()
	t.reloadMu.Unlock()
	if t.stopProbes != nil {
		t.stopProbes()
	}
	if t.stopReconcile != nil {
		t.stopReconcile()
	}
	if t.stopHubFailover != nil {
		t.stopHubFailover()
	}
	// Stop the DNS re-resolution loop between hub-failover and the engine teardown (T74): no
	// re-resolve may race the engine peer's install/repoint or the socket close.
	if t.stopResolution != nil {
		t.stopResolution()
	}
	// Stop the WG-session monitor before the engine teardown (I2): no IpcGet may race the
	// engine's Close.
	if t.stopSession != nil {
		t.stopSession()
	}
	// Withdraw the default-route wiring (I6) BEFORE the engine teardown, while wanbond0
	// still exists: with tun_persist=true the interface survives Close, so its routes
	// must be explicitly removed here; with the default teardown dev.Close destroys the
	// interface (and the kernel drops its routes with it), so removeRoutes is idempotent
	// either way (it tolerates an already-gone device/route). A tunnel with no
	// default-route peer has an empty set and this is a no-op.
	if len(t.routePrefixes) > 0 {
		if err := removeRoutes(t.name, t.routePrefixes); err != nil {
			t.log.Warn("default-route teardown: could not remove routes", "error", err.Error())
		}
	}
	t.dev.Close()
	t.releaseOnce.Do(func() { globalAmneziaGuard.release(t.amnezia) })
}

// engineLogger adapts the amneziawg engine's logger onto wanbond's structured
// logger under a "wg" component. The engine is verbose only when the daemon runs
// at debug level; otherwise only its errors surface.
//
// everHadLivePath is the bind-level "ever had a live path" predicate (I4,
// bind.Multipath.EverHadLivePath): until the FIRST configured path reaches
// liveness up, the engine's "Failed to send handshake initiation: %w"
// (bind.ErrNoHealthyPath) is expected — every path starts Down and the boot-time
// probe race hasn't settled yet — so it would otherwise spam ERROR on every normal
// start. During that warmup window this adapter coalesces every such record into
// exactly ONE "waiting for path liveness" INFO line (not one per failed init) and
// emits none at ERROR; once everHadLivePath reports true it stops intercepting —
// the SAME error after a path has been up is a genuine outage and stays ERROR.
// Any OTHER Errorf record (not wrapping ErrNoHealthyPath) is unaffected and always
// logs at ERROR, warmup or not. Relates D37 (the wasted-first-init defect itself is
// investigate-flow-owned; this only fixes log severity).
func engineLogger(lg log.Logger, level string, everHadLivePath func() bool) *awgdevice.Logger {
	wg := lg.Component("wg")
	verbosef := func(string, ...any) {}
	if strings.EqualFold(strings.TrimSpace(level), "debug") {
		verbosef = func(format string, args ...any) { wg.Debug(fmt.Sprintf(format, args...)) }
	}
	var warmupInfoLogged atomic.Bool
	errorf := func(format string, args ...any) {
		if !everHadLivePath() && argsHaveNoHealthyPath(args) {
			if warmupInfoLogged.CompareAndSwap(false, true) {
				wg.Info("waiting for path liveness")
			}
			return
		}
		wg.Error(fmt.Sprintf(format, args...))
	}
	return &awgdevice.Logger{
		Verbosef: verbosef,
		Errorf:   errorf,
	}
}

// argsHaveNoHealthyPath reports whether any of an Errorf call's variadic args is (or
// wraps) bind.ErrNoHealthyPath. The engine passes the error value itself as a %v/%w
// arg (e.g. peer.go's "%v - Failed to send handshake initiation: %v", peer, err), so
// this checks the args directly with errors.Is rather than string-matching the
// formatted message, which would be fragile against wording changes.
func argsHaveNoHealthyPath(args []any) bool {
	for _, a := range args {
		if err, ok := a.(error); ok && errors.Is(err, bind.ErrNoHealthyPath) {
			return true
		}
	}
	return false
}

// bootEndpoint is a peer's initial engine endpoint derived from the bounded boot resolve: the
// flattened head of its seeded failoverSpecs, valid only when at least one spec has an expansion.
// An invalid boot endpoint means the peer boots endpoint-less (tolerant boot).
type bootEndpoint struct {
	ap    netip.AddrPort
	valid bool
}

// bootEndpoints is the outcome of the bounded initial resolve: the resolver constructed for
// hostname re-resolution (nil when no peer carries a hostname spec — the wiring is then provably
// inert, Q29), the per-peer seeded failoverSpecs (hostname expansions filled from the boot resolve,
// literals fixed), and the per-peer boot endpoint the UAPI render installs. specs and endpoints are
// indexed 1:1 with cfg.WireGuard.Peers.
type bootEndpoints struct {
	resolver  dnsresolve.Resolver
	specs     [][]failoverSpec
	endpoints []bootEndpoint
}

// resolveBootEndpoints performs the bounded initial hostname resolve (Q30) and derives, per peer,
// the seeded failoverSpecs and the boot endpoint the UAPI render installs. It constructs the
// resolver AT MOST ONCE, and ONLY when some peer carries a hostname endpoint spec — a config with
// zero hostname specs never invokes newResolver, so its wiring is provably inert (Q29). A literal
// spec is seeded verbatim (byte-for-byte the pre-G5 behaviour); a hostname spec is resolved under
// the [dns] per-lookup timeout and family-filtered. A lookup that fails, times out, or yields no
// usable record leaves that spec EMPTY — the peer boots endpoint-less and the re-resolution loop
// installs it on first success (R70). A resolver that fails to construct is logged and treated as
// absent (every hostname spec then boots empty), since re-resolution must never fail bring-up.
func resolveBootEndpoints(cfg *config.Config, newResolver resolverFactory, lg log.Logger) bootEndpoints {
	peers := cfg.WireGuard.Peers
	b := bootEndpoints{
		specs:     make([][]failoverSpec, len(peers)),
		endpoints: make([]bootEndpoint, len(peers)),
	}

	hasName := false
	for _, p := range peers {
		for _, s := range p.EndpointSpecs {
			if s.IsName {
				hasName = true
			}
		}
	}
	if hasName {
		if r, err := newResolver(); err != nil {
			lg.Warn("dns: could not construct resolver; hostname endpoints boot endpoint-less and will not re-resolve",
				"error", err.Error())
		} else {
			b.resolver = r
		}
	}

	fams := pathFamiliesFromPaths(cfg.Paths)
	for i, p := range peers {
		specs := make([]failoverSpec, len(p.EndpointSpecs))
		for j, s := range p.EndpointSpecs {
			if !s.IsName {
				specs[j] = failoverSpec{spec: s, addrs: []netip.AddrPort{s.Addr}}
				continue
			}
			var addrs []netip.AddrPort
			if b.resolver != nil {
				addrs = bootResolveHostname(b.resolver, s, fams, cfg.DNS.Timeout, lg)
			}
			specs[j] = failoverSpec{spec: s, addrs: addrs}
		}
		b.specs[i] = specs
		// The boot endpoint is the FLATTENED head — the first spec (in TOML order) with a
		// non-empty expansion. None ⇒ endpoint-less boot.
		for _, sp := range specs {
			if len(sp.addrs) > 0 {
				b.endpoints[i] = bootEndpoint{ap: sp.addrs[0], valid: true}
				break
			}
		}
	}
	return b
}

// bootResolveHostname does one context-bounded lookup for a hostname spec at boot and returns the
// ordered, family-filtered []netip.AddrPort (empty on any failure/timeout/empty-result — the caller
// then boots that spec endpoint-less). The timeout is the [dns] per-lookup timeout (kept > 0 by
// config validation); a non-positive value falls back to an unbounded context, matching
// resolution.lookupContext, but Up should never pass one.
func bootResolveHostname(resolver dnsresolve.Resolver, s config.EndpointSpec, fams pathFamilies, timeout time.Duration, lg log.Logger) []netip.AddrPort {
	ctx := context.Background()
	if timeout > 0 {
		var cancel context.CancelFunc
		ctx, cancel = context.WithTimeout(ctx, timeout)
		defer cancel()
	}
	addrs, _, _, err := resolver.Lookup(ctx, s.Host)
	if err != nil {
		lg.Info("dns: initial resolve failed; endpoint boots deferred to the re-resolution loop",
			"host", s.Host, "error", err.Error())
		return nil
	}
	eps := orderAddrPorts(addrs, s.Port, fams)
	if len(eps) == 0 {
		lg.Info("dns: initial resolve yielded no usable record for local path families; endpoint boots deferred",
			"host", s.Host)
		return nil
	}
	return eps
}

// uapiConfig renders cfg into the newline-delimited UAPI set string the engine's
// IpcSet consumes. Keys are lowercase hex (UAPI's on-the-wire encoding), NOT the
// base64 form the TOML carries. Amnezia obfuscation keys are emitted only when the
// block is configured; an all-zero Amnezia block leaves the engine in plain
// WireGuard mode. The same amnezia parameters are applied on BOTH roles (edge and
// concentrator) as defense-in-depth — they must match end to end for the handshake
// to succeed (config validation makes each end specify a complete profile, D1).
func uapiConfig(cfg *config.Config, bootEndpoints []bootEndpoint) (string, error) {
	var b strings.Builder

	priv := cfg.WireGuard.PrivateKey.Bytes()
	fmt.Fprintf(&b, "private_key=%s\n", hex.EncodeToString(priv[:]))
	if cfg.Role == config.RoleConcentrator {
		fmt.Fprintf(&b, "listen_port=%d\n", cfg.WireGuard.ListenPort)
	}
	writeAmnezia(&b, cfg.Amnezia)

	for i, peer := range cfg.WireGuard.Peers {
		pub := peer.PublicKey.Bytes()
		fmt.Fprintf(&b, "public_key=%s\n", hex.EncodeToString(pub[:]))
		// The engine peer's endpoint is built ONLY from a resolved flattened entry (Q30): the
		// boot endpoint is the head of the peer's seeded failoverSpecs — a literal's fixed address
		// for an all-literal peer (byte-for-byte the pre-G5 render, Endpoints[0]), or a hostname's
		// boot-resolved head. When nothing resolved (a hostname peer whose name did not resolve in
		// the boot window, or a resolver-less concentrator peer with no endpoint at all) the boot
		// endpoint is INVALID and no endpoint line is emitted — the peer boots endpoint-less
		// (tolerant boot), and for a hostname peer the re-resolution loop installs it on first
		// success (R70). Switching to a standby endpoint on hub loss is the failover controller's
		// job, not this initial render.
		if ep := bootEndpoints[i]; ep.valid {
			fmt.Fprintf(&b, "endpoint=%s\n", ep.ap.String())
			// A keepalive keeps the edge->concentrator session warm and lets the
			// concentrator relearn the edge endpoint after a NAT rebind; only the
			// initiating (edge) side sets it.
			fmt.Fprintf(&b, "persistent_keepalive_interval=%d\n", keepaliveSeconds)
		}
		if len(peer.AllowedIPs) == 0 {
			return "", fmt.Errorf("peer %d (%s): at least one allowed_ip is required", i, hex.EncodeToString(pub[:8]))
		}
		for _, cidr := range peer.AllowedIPs {
			for _, split := range splitDefaultRoute(cidr) {
				fmt.Fprintf(&b, "allowed_ip=%s\n", split)
			}
		}
	}
	return b.String(), nil
}

// splitDefaultRoute expands a literal 0.0.0.0/0 or ::/0 allowed_ip entry into
// its equivalent pair of /1 prefixes (D35, I6): amneziawg-go's engine wedges
// the handshake when handed the literal all-routes /0 prefix, so uapiConfig
// always renders the split form here and the engine never receives a literal
// /0 — regardless of the peer's mode. Any other prefix, including one that
// fails to parse (allowed_ips carries no syntax validation upstream), passes
// through unchanged.
func splitDefaultRoute(cidr string) []string {
	p, err := netip.ParsePrefix(cidr)
	if err != nil || p.Bits() != 0 {
		return []string{cidr}
	}
	if p.Addr().Is4() {
		return []string{"0.0.0.0/1", "128.0.0.0/1"}
	}
	return []string{"::/1", "8000::/1"}
}

// defaultRoutePrefixes computes the route set to install into wanbond0 for
// mode=default-route (I6, Q41): the wg-quick-style split of every default-route
// peer's allowed_ips (0.0.0.0/0 → the two /1s, ::/0 → its two /1s), REUSING the
// same splitDefaultRoute helper uapiConfig renders the engine allowed_ips with, so
// the installed routes match the internal split exactly. It returns nil unless some
// peer explicitly opts into default-route mode — the regression guard: a config
// without the mode installs no route at all. mode=default-route is edge-only (config
// validation rejects it on the concentrator), so this is naturally empty there. An
// allowed_ip that fails to parse is skipped (allowed_ips carries no upstream syntax
// validation, matching splitDefaultRoute's own tolerance); the split entries always
// parse.
func defaultRoutePrefixes(cfg *config.Config) []netip.Prefix {
	var prefixes []netip.Prefix
	for _, peer := range cfg.WireGuard.Peers {
		if peer.Mode != config.PeerModeDefaultRoute {
			continue
		}
		for _, cidr := range peer.AllowedIPs {
			for _, split := range splitDefaultRoute(cidr) {
				p, err := netip.ParsePrefix(split)
				if err != nil {
					continue
				}
				prefixes = append(prefixes, p.Masked())
			}
		}
	}
	return prefixes
}

// keepaliveSeconds is the edge's persistent-keepalive interval.
const keepaliveSeconds = 25

// writeAmnezia emits the nine amneziawg obfuscation UAPI keys, but only when the
// block is configured. When amnezia is unused, wanbond leaves the engine's
// PROCESS-GLOBAL message-type state untouched (see the amneziaGuard invariant).
// Config validation guarantees a configured block is complete and self-consistent
// (D1), and applyDefaults has already filled the standard magic headers (1..4)
// when they were omitted, so the emitted set never carries an h*=0 sentinel.
func writeAmnezia(b *strings.Builder, a config.Amnezia) {
	if !a.Configured() {
		return
	}
	fmt.Fprintf(b, "jc=%d\njmin=%d\njmax=%d\ns1=%d\ns2=%d\nh1=%d\nh2=%d\nh3=%d\nh4=%d\n",
		a.Jc, a.Jmin, a.Jmax, a.S1, a.S2, a.H1, a.H2, a.H3, a.H4)
}

package bind

import (
	"crypto/rand"
	"errors"
	"fmt"
	"net"
	"net/netip"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	"github.com/amnezia-vpn/amneziawg-go/conn"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
	"github.com/7mind/wanbond/internal/reseq"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// socketRecvBuffer is the SO_RCVBUF requested on every per-path socket, matching
// wireguard-go's StdNetBind (~7 MiB). A large receive buffer absorbs the bursts a
// bonded, reordered flow delivers while the userspace engine catches up; the
// pass-through P0 Bind used the OS default and lost datagrams under load (P0
// findings §1/§2). The kernel silently caps the request at net.core.rmem_max, so
// the effective size may be smaller on an untuned host — best-effort by design.
const socketRecvBuffer = 7 << 20

// multipathBatchSize is the number of datagrams a ReceiveFunc / Send handles per
// call. T12 keeps it at 1 (one syscall per datagram, per path); GSO/GRO batching
// is best-effort future work (P0 findings §2) tracked separately and does not
// change the wire format.
const multipathBatchSize = 1

// maxDatagram bounds a single received outer datagram. It comfortably exceeds a
// full-MTU inner packet plus every outer/WG/amnezia-junk overhead.
const maxDatagram = 65535

// Receive-resequencer tuning (T18), sized against P0 findings §6.
//
// resequencerWindow is the maximum span of outer-seq positions the receive
// resequencer buffers while it waits for an out-of-order frame. WG's inner RFC
// 6479 anti-replay window is 8128 messages (docs/p0-findings.md §6); the window
// here sits ~4x below that, so even a worst-case burst of reordered/held frames
// stays comfortably inside the inner filter's tolerance while spanning far more
// packets than the measured ~19 ms emulated cross-path skew (and the larger,
// more variable real Starlink/5G skew) needs at realistic per-path rates.
//
// resequencerTimeout bounds how long a head-of-line-blocked run is held for a
// missing (presumed-lost) lower frame before that gap is skipped and the run
// released. It caps the added latency — and the stall a slow/lossy path can
// impose on the whole bond (P0 §7 head-of-line concern) — to a few multiples of
// a Starlink RTT (~45 ms) rather than holding a gap forever.
const (
	resequencerWindow  = 2048
	resequencerTimeout = 250 * time.Millisecond
)

// defaultMaxDemuxSources caps the source->peer demux map (peerBySource), the
// PROVISIONAL/unbound-source tracking state whose growth an attacker probes at
// bootstrap (Q26/Q27). It is sized SEPARATELY from the steady-state peer set
// (m.peersByName, bounded by the static configured [[wireguard.peers]]): a source
// enters this map only on an authenticated PROBE (T88), but a party holding ONE
// valid psk could otherwise bind an unbounded number of distinct spoofed sources to
// its OWN peer and exhaust memory. On exhaustion a NEW source's binding is dropped
// (drop-on-exhaustion, bootstrap degrades) — an already-bound (live) source is NEVER
// evicted. Roam/re-bind of an already-present source (T90) does not grow the map, so
// it is never blocked by the cap. A dead peer's bindings are reclaimed on teardown
// (TearDownPeer), freeing slots. The default is generous relative to any realistic
// concentrator's peer×roam-churn count yet bounds the flood surface.
const defaultMaxDemuxSources = 1024

var (
	// ErrNoHealthyPath is exported (I4) so the device-package engineLogger adapter can
	// errors.Is-match it against the engine's wrapped Errorf args to gate the startup
	// no-healthy-path warmup coalescing without string-matching the log message.
	ErrNoHealthyPath = errors.New("bind: no healthy path with a known remote endpoint")
	// errPacerShedding is returned by Send when the scheduler shed the datagram for
	// pacing (PickPaced) while paths are healthy — deliberate rate limiting, NOT an
	// outage. It is DISTINCT from ErrNoHealthyPath so operator logs and the e2e
	// log-grep harness can tell shedding from total path failure (the drop behavior is
	// identical to the pre-existing no-path case; only the diagnostic differs). The
	// coalesced, rate-limited "pacer shedding" record is emitted by the scheduler.
	errPacerShedding = errors.New("bind: datagram shed by send pacer (paths healthy, rate limited)")
	errClosed        = net.ErrClosed
)

// sharedPathState is the per-SOCKET state of one configured uplink, SHARED across
// every peer bound beneath the Bind: its stable path-id, source address, and the
// source-bound UDP socket (drained by exactly one Bind-owned readLoop). A concentrator
// front-ends many peers on the SAME socket, so this identity is owned once per socket
// and referenced by every peer's per-(peer,path) view (peerPathState). On the single-peer
// edge/hub there is exactly one peer, so each shared path has exactly one peerPathState.
// The deferred-path machinery (deferredPath, m.deferred) likewise operates on this shared
// socket layer — a runtime add/remove of a shared path fans the per-(peer,path) state out
// to every bound peer (see attachSharedPathLocked / RemovePath).
type sharedPathState struct {
	name string
	id   uint8
	src  netip.Addr
	conn *net.UDPConn

	// views is the per-peer VIEW set of THIS shared socket — one peerPathState per bound
	// peer — published copy-on-write through an atomic.Pointer so the single Bind-owned
	// readLoop demuxes an inbound datagram to its owning peer's view WITHOUT m.mu on the
	// receive hot path (the same lock-free-publish discipline peersView/resequencer use).
	// It is (re)published under m.mu at every fan-out site (Open / attachPeerPathLocked /
	// deferred promote, and each concentrator peer bind). On the single-peer edge/hub it
	// holds exactly one entry (the primary's view), which handleInbound reads as "no demux
	// needed" — the byte-identical fast path. len(views)>1 marks a shared concentrator
	// socket whose datagrams must be source-demuxed to the owning peer (T88).
	views atomic.Pointer[[]*peerPathState]
}

// addViewLocked publishes pp as a per-peer view of this shared socket for the lock-free
// receive demux (T88). Copy-on-write: it republishes a NEW slice with pp appended, so a
// readLoop mid-iteration over the previously-published snapshot is never disturbed. The
// caller holds m.mu (every fan-out site does), which serializes writers; readers Load
// without a lock.
func (sp *sharedPathState) addViewLocked(pp *peerPathState) {
	old := sp.views.Load()
	var next []*peerPathState
	if old != nil {
		next = make([]*peerPathState, len(*old), len(*old)+1)
		copy(next, *old)
	}
	next = append(next, pp)
	sp.views.Store(&next)
}

// peerPathState is one peer's per-(peer,path) VIEW of a shared uplink: that peer's own
// decode Codec (each path receives on its own goroutine, so the Codec's scratch is never
// shared), the peer's own learned/configured return remote, the peer's own probe
// initiator for this path, and the peer's own per-path OUTER-wire byte counters. The
// remote is either configured (edge dest_addr / peer endpoint) or LEARNED from inbound
// traffic (concentrator) — but it lives strictly BELOW the engine's single virtual
// endpoint, so the engine never sees this per-(peer,path) bookkeeping churn.
//
// It EMBEDS its *sharedPathState so the socket identity (name/id/src/conn) is reached
// transparently, and back-references the owning peerState so a receive handler resolves
// exactly that peer's resequencer/reflector/FEC decoder.
type peerPathState struct {
	*sharedPathState
	peer  *peerState
	codec *frame.Codec
	// prober is this (peer,path)'s own probe initiator (nil when the bind runs without the
	// probe transport). It is set at path creation and immutable for the path's life,
	// so the Bind-owned receive goroutine reaches it via the peerPathState it already
	// holds — NOT through a shared, dynamically-mutated probers slice — which is
	// what keeps echo handling race-free while paths are added/removed at runtime (T30).
	prober *telemetry.Prober

	// txBytes/rxBytes are cumulative OUTER-wire byte counters for this (peer,path), the
	// per-path traffic accounting the /metrics exposition reports (T23). txBytes counts
	// the DATA-frame wire bytes this path egresses on the Send hot path; rxBytes counts
	// every outer datagram this path's readLoop receives (DATA, PROBE, and echo alike —
	// the true received wire volume). They are atomics so the send/receive hot paths
	// increment them WITHOUT taking m.mu (lock-free), and the scrape/snapshot path reads
	// them with a plain atomic Load; a single writer per counter (Send holds m.mu while
	// choosing the path, and each path has exactly one readLoop) means the Add is
	// uncontended in the common case. "Bytes on Starlink vs 5G" — the data-thrift signal
	// (requirement 2) — is exactly txBytes: when the weighted scheduler collapses to the
	// primary under sub-capacity load, the backup path's Send count stays ~flat.
	txBytes atomic.Uint64
	rxBytes atomic.Uint64

	mu        sync.Mutex
	remote    netip.AddrPort
	hasRemote bool
}

// peerState holds the per-PEER datapath state that was a process-global singleton before
// the multi-peer concentrator split: the SINGLE virtual endpoint the engine holds for this
// peer, the peer's send scheduler, its own outer-seq space, its shared send Codec, its
// probe reflector, its receive resequencer and FEC send/receive planes, its per-path probe
// initiators, and its per-(peer,path) views over the shared sockets. The single-peer
// edge/hub constructs EXACTLY ONE peerState (so behaviour is byte-identical to the pre-split
// singleton — Multipath embeds it as the primary and the datapath reaches its fields through
// that embed); the concentrator constructs one peerState per bound peer. resequencer and
// fecRecv stay atomic.Pointer, and outerSeq atomic, so the lock-free receive/send fast paths
// read them WITHOUT m.mu.
type peerState struct {
	// name is the peer id/name, the key under which Multipath.peersByName holds this peer.
	// Empty on the single-peer edge/hub (there is only one peer to key).
	name string

	// psk is THIS peer's effective pre-shared key: the sole seam from which every frame
	// Codec this peer derives (its sendCodec and each per-(peer,path) receive codec, via
	// newCodec) and its probe Reflector authenticate. The single-peer edge/hub sets it to
	// the one configured psk (so behaviour is byte-identical to the pre-split singleton);
	// the concentrator sets a DIFFERENT psk per bound peer, so one peer's codec/reflector
	// rejects another peer's frames (T84). NewCodec/NewReflector PSK-derivation itself is
	// unchanged — only WHICH psk each peer feeds them differs.
	psk config.Key

	// Immutable per-peer collaborators, built at construction and persisting across the
	// Open→Close socket lifecycle (the concentrator pins virt's destination once for the
	// process life, so virt in particular must NOT be recreated per Open).
	virt      *udpEndpoint
	scheduler sched.Scheduler
	reflector *telemetry.Reflector
	// newProber mints a prober for a path admitted to THIS peer at runtime (T30); nil
	// disables runtime path addition for the peer (a bind without the probe transport).
	newProber ProberFactory
	// probers is this peer's BOOT-TIME per-path probe initiator set, in durable-membership
	// (m.defs) order — bound AND deferred — shared with this peer's scheduler. At Open each
	// bound entry is bound onto its peerPathState (pp.prober), and thereafter the hot paths
	// reach a path's prober through the peerPathState — never by indexing this slice — so a
	// runtime path add/remove cannot race echo handling. Nil when the peer runs without the
	// probe transport; a nil here also gates the whole probe loop off.
	probers []*telemetry.Prober

	// Per-Open state, (re)built by Open and cleared by Close.
	sendCodec *frame.Codec
	paths     []*peerPathState
	outerSeq  atomic.Uint64
	// resequencer is this peer's shared T18 receive resequencing buffer. Published
	// atomically so the per-path readLoop goroutines read it WITHOUT m.mu.
	resequencer atomic.Pointer[reseq.Resequencer]
	// FEC datapath (T24), per peer. Both published atomically like resequencer so the
	// lock-free receive fast path Loads fecRecv, and the lazy re-instantiation on re-bind
	// (ensurePeerReceiveInstantiated, on a readLoop that must not take m.mu) can Store
	// fecSend without racing Send's under-m.mu Load. The ENCODER inside fecSend is still
	// mutated (Admit/Tick) only under m.mu — the atomic pointer governs publication of the
	// fecSender object, not its encoder's single-writer discipline. Both nil when FEC is off.
	fecSend atomic.Pointer[fecSender]
	fecRecv atomic.Pointer[fecReceiver]

	// lifecycleMu serializes lazy (re)instantiation of the heavy trio (resequencer, fecRecv,
	// fecSend) on a readLoop goroutine (ensurePeerReceiveInstantiated) against teardown's
	// clearing of that trio (teardownPeerLocked), so a teardown interleaving mid-instantiation
	// can never leave a half-published plane (a fecRecv/fecSend without its resequencer) nor
	// resurrect a plane on a torn-down peer that the next re-bind then reuses stale. It is a
	// LEAF lock taken either ALONE (instantiation — which must never take m.mu, so Close's
	// readersWG.Wait under m.mu cannot deadlock on it) or UNDER m.mu (teardown), giving the
	// single fixed order m.mu -> lifecycleMu and no cycle (instantiation never reaches for m.mu).
	lifecycleMu sync.Mutex
}

// newPeerState builds the durable per-peer datapath state whose probe Reflector — and,
// through ps.psk, every frame Codec this peer later derives in Open/AddPath (its sendCodec
// and each per-(peer,path) receive codec, via newCodec) — authenticate under THIS peer's
// psk. It is the seam that replaces the pre-split single-psk assumption (T84): the
// single-peer edge/hub mints exactly one (the primary) from the sole configured psk, while
// the concentrator mints one per bound peer from that peer's DIFFERENT effective psk, so a
// peerState built from a different psk gets its own codec/reflector and cross-psk frames are
// rejected. virt is created here (not per Open) because the concentrator pins its destination
// once for the process life. The Reflector draws its per-path challenges from crypto/rand,
// exactly as before. The per-Open fields (sendCodec, paths, resequencer, FEC planes) are
// left zero for Open to (re)build.
func newPeerState(name string, psk config.Key, scheduler sched.Scheduler, newProber ProberFactory, probers []*telemetry.Prober) *peerState {
	return &peerState{
		name:      name,
		psk:       psk,
		virt:      &udpEndpoint{},
		scheduler: scheduler,
		reflector: telemetry.NewReflector(psk, rand.Reader),
		newProber: newProber,
		probers:   probers,
	}
}

// newCodec derives a fresh frame Codec bound to THIS peer's psk — the send Codec at Open and
// each per-(peer,path) receive Codec share the derivation but not the instance, since a Codec
// is not safe for concurrent use (each receive path decodes on its own goroutine). Deriving
// from ps.psk (not a Multipath-wide key) is what makes a path's receive Codec the codec of the
// peer the path is bound to (T84).
func (ps *peerState) newCodec() (*frame.Codec, error) {
	return frame.NewCodec(ps.psk)
}

// deferredPath is a configured path whose WELL-FORMED source_addr was not yet
// assignable at Open (net.ListenUDP -> EADDRNOTAVAIL: no interface holds the
// address, e.g. a 5G modem with no DHCP lease at boot). Rather than tear the whole
// bond down, Open records the path here instead of binding it: the tunnel comes up
// on the paths that DID bind, and this path stays DOWN — its prober, never fed an
// echo, reports StateDown, which the scheduler excludes from Pick, exactly as the
// runtime path-down model treats a live-but-silent path. It carries the boot-time
// prober so the T55 background reconcile that retries the bind reuses the SAME
// path-id stamp instead of minting a new one. prober is nil only on a bind without
// the probe transport, which never defers (see Open).
type deferredPath struct {
	def    config.Path
	prober *telemetry.Prober
}

func (ps *peerPathState) setRemote(ap netip.AddrPort) {
	ps.mu.Lock()
	ps.remote, ps.hasRemote = ap, true
	ps.mu.Unlock()
}

func (ps *peerPathState) getRemote() (netip.AddrPort, bool) {
	ps.mu.Lock()
	defer ps.mu.Unlock()
	return ps.remote, ps.hasRemote
}

// Multipath is the P1 bonding conn.Bind: one UDP socket per configured path
// (bound to the path's source address), all fronted by a SINGLE stable virtual
// endpoint the engine holds per peer. Send wraps each opaque WireGuard datagram
// in an outer DATA frame (own outer-seq + path-id) and picks a path; one
// Bind-owned reader per path unwraps DATA frames into the shared resequencer, and
// a SINGLE engine-facing ReceiveFunc drains it and hands the inner WG datagram up
// under the shared virtual endpoint (the fan-in that lets paths be added/removed at
// runtime without the engine spawning receive goroutines — T30). It replaces
// bind.Passthrough behind the same conn.Bind seam (device wiring is unchanged).
//
// Lifecycle: the sockets live for the duration of an Open→Close span, NOT the
// Multipath's whole life. The amneziawg engine calls Close() before every Open()
// (device.upLocked → BindUpdate → closeBindLocked, and on IpcSet listen_port /
// route-change events) and cycles Close↔Open on Down/Up, so — exactly like
// conn.StdNetBind — Open creates the per-path sockets and Close tears them down
// AND clears the path state so the next Open rebuilds from scratch. The "closed"
// state is simply "no bound sockets" (len(paths)==0); there is no separate sticky
// flag that a later Open would have to reset.
//
// Path policy: an injected sched.Scheduler (T15) chooses the egress path per
// datagram. The P1 MVP wires an active-backup scheduler (all traffic on the
// preferred primary, transparent failover to a backup on a T13 path-DOWN signal
// with failback hysteresis); the weighted/FEC-aware policy (T21) is a different
// Scheduler swapped in here with no Bind change. No FEC/resequencing yet
// (P2/P3), but every DATA frame carries its outer-seq and path-id so T18/T24 can
// consume them.
// ProberFactory mints a *telemetry.Prober for a path admitted at runtime (T30),
// stamped with the given stable path-id. The device wires it capturing the SAME
// per-boot session id, prober config, clock, PSK, and logger the boot-time probers
// were built with, so a runtime path's liveness is measured identically to a
// boot-time path (its probes join the same session so the peer's reflector adopts
// them without a challenge reset). It is nil on a bind built without the probe
// transport (the T12 unit tests), which therefore cannot add paths at runtime.
type ProberFactory func(name string, id uint8) *telemetry.Prober

type Multipath struct {
	defs []config.Path

	// classify maps each outbound datagram to its pacer traffic class from the inner
	// WireGuard message type, parameterized by the tunnel's Amnezia obfuscation profile
	// so a WireGuard control frame (handshake/keepalive) is recognised — and pacing-
	// exempted — under advanced security too, not only in vanilla mode (defect D22). It
	// is immutable after construction and holds no lock, so Send reads it off m.mu.
	classify wgClassifier

	// deferredListen binds a reconciled deferred path's socket (T55 background
	// reconcile). It is an injection seam: the default pins the source IP unless dev is
	// set (net.ListenUDP / listenPath, matching AddPath's runtime bind — I5), and a test
	// overrides it to drive the deferred→bound transition deterministically — a
	// source_addr "becoming assignable" — without a real interface address having to
	// appear on the host. dev is resolveForcedDeviceBind's decision for the deferred
	// path's resolved BindMode, computed by reconcileDeferred before the call. Immutable
	// after construction, never nil.
	deferredListen func(src netip.Addr, port uint16, dev string) (*net.UDPConn, error)

	// resolveDeviceBind decides AddPath's and reconcileDeferred's per-path forced-
	// device bind (I5): whether a path's RESOLVED BindMode is config.BindModeDevice,
	// and if so, the interface its source_addr currently resolves to (see
	// resolveForcedDeviceBind — it has no other-path contention to check, unlike
	// Open's planPathBinds/selectDeviceBinds). It is an injection seam mirroring
	// deferredListen: the default is the real resolveForcedDeviceBind (a
	// net.Interfaces() snapshot), and a test overrides it to drive a BindModeDevice
	// path's dev deterministically without a real interface having to appear on the
	// host (T106 round 2). Immutable after construction, never nil.
	resolveDeviceBind func(src netip.Addr, mode config.BindMode) string

	// addPathListen binds AddPath's runtime-admitted path's socket. It is an
	// injection seam mirroring deferredListen, scoped to AddPath's OWN call site:
	// AddPath calls the package-level listenPath directly (it is not routed through
	// deferredListen, which only reconcileDeferred drives), so without this seam no
	// test can observe what dev AddPath actually threads into the bind — resolving a
	// BindModeDevice interface via resolveDeviceBind and then discarding it at the
	// listen call passes the full suite (T106 round 3). The default is the real
	// listenPath; a test overrides it to capture the dev argument deterministically
	// without a real interface having to appear on the host. Immutable after
	// construction, never nil.
	addPathListen func(src netip.Addr, port uint16, dev string) (*net.UDPConn, error)

	mu sync.Mutex

	// The PRIMARY peer, embedded so the single-peer datapath (Send, the receive drainer,
	// the probe loop) and the existing single-peer tests reach its fields — virt,
	// scheduler, reflector, newProber, probers, sendCodec, paths, outerSeq, resequencer,
	// fecSend/fecRecv — transparently through promotion, keeping behaviour byte-identical
	// to the pre-split singleton. It is peers[0]; the concentrator's additional peers live
	// in peers/peersByName. The former process-global resequencer/outerSeq/scheduler now
	// live on this peerState, NOT on Multipath.
	*peerState

	// peers is every bound peer (len 1 on the single-peer edge/hub). The runtime shared-
	// path add/remove fan-out iterates it so per-(peer,path) state is created/torn-down for
	// EVERY currently-bound peer (attachSharedPathLocked / RemovePath). peersByName keys
	// them by peer id/name.
	peers       []*peerState
	peersByName map[string]*peerState
	// peersView is the LOCK-FREE snapshot of the bound peer set the single engine-facing
	// receive drainer iterates (newReceiveFunc). m.peers is mutated only under m.mu (peer
	// wiring / fan-out); every mutation republishes this pointer (republishPeersLocked) so
	// the drainer enumerates EVERY bound peer's resequencer WITHOUT taking m.mu on the
	// receive hot path — the same lock-free-publish discipline resequencer/fecRecv use. It
	// is never nil after construction (the constructor publishes the primary-only view).
	peersView atomic.Pointer[[]*peerState]
	// peerByEndpoint is the inbound endpoint-keyed demux placeholder (still unused today: the
	// single-peer edge/hub needs no demux, and the source-keyed binding below is what the
	// concentrator receive path routes on).
	peerByEndpoint map[netip.AddrPort]*peerState
	// peerBySource is the inbound source-demux map: a learned source address → the peer it was
	// bound to by an authenticated PROBE (T88). The concentrator's per-socket readLoops resolve
	// a datagram's source to its owning peer through it; a source is bound ONLY on the first
	// PROBE that MAC-verifies under a peer's psk (D9/D11: bindings, like remotes, are learned
	// only from authenticated PROBEs). It is published copy-on-write through an atomic.Pointer
	// so the receive hot path resolves a bound source with a lock-free Load (no m.mu — a reader
	// must never block on m.mu, since Close waits on the readers WHILE holding it), and a new
	// binding is installed lock-free by a CAS republish of a copy with the entry added
	// (bindSourceToPeer). Nil until the first binding; the single-peer edge/hub never consults
	// it (one peer owns every socket — handleInbound's fast path skips the demux entirely).
	peerBySource atomic.Pointer[map[netip.Addr]*peerState]
	// maxDemuxSources caps peerBySource (the provisional/unbound-source demux state) so a
	// bootstrap flood cannot grow it without bound (Q26/Q27, see defaultMaxDemuxSources). Set
	// once at construction and read on the lock-free bind path (bindSourceToPeer); a test may
	// lower it to exercise cap-exhaustion. Zero (never set) means "no cap".
	maxDemuxSources int
	// peerByVirt routes an OUTBOUND Send to its owning peer: the engine hands Send the
	// single virtual endpoint (*udpEndpoint) it holds for a peer, and this map resolves
	// that pointer to the peer's datapath state (outerSeq, scheduler, sendCodec, fecSend,
	// per-(peer,path) set). It is the SEND-side dual of peerByEndpoint/peerBySource (which
	// demux INBOUND datagrams). Each peer's virt is DISTINCT, so the lookup is exact; an
	// endpoint not in this map is an unknown peer, which Send refuses rather than
	// misrouting onto some other peer's paths. The primary is registered at construction;
	// the concentrator registers each additional peer as it binds it. Read under m.mu on
	// the Send path; written under m.mu (or at single-threaded construction).
	peerByVirt map[*udpEndpoint]*peerState

	// shared is the SHARED per-socket path list (the sockets themselves), rebuilt from
	// m.defs on every Open and mutated by the runtime add/remove. Each bound peer holds a
	// peerPathState VIEW over a subset of these; on the single-peer edge/hub primary.paths
	// is index-aligned with shared. len(shared)==0 is the "closed" (no sockets) state.
	shared []*sharedPathState

	// deferred holds the configured paths whose well-formed source_addr was not yet
	// assignable at the last Open (EADDRNOTAVAIL). They are NOT in shared or the
	// scheduler — the tunnel runs on the paths that bound — but are recorded here,
	// index-independent of shared, for the T55 background reconcile to retry as their
	// addresses appear. Rebuilt from scratch on every Open; guarded by m.mu. The deferred-
	// path machinery is SHARED (per-socket): a promoted deferred path fans its per-(peer,
	// path) state out to every peer exactly as a runtime AddPath does.
	deferred []deferredPath
	// defaultRemote is the fallback per-path remote (the peer's wireguard
	// endpoint) applied to any path without its own dest_addr. It may be set by
	// ParseEndpoint BEFORE Open, so it is stored here and applied at Open time.
	defaultRemote    netip.AddrPort
	hasDefaultRemote bool

	// fecCfg / adaptiveCfg are the FEC configuration (T24/T29), shared by every peer; the
	// per-peer fecSend/fecRecv runtime state Open builds from them lives on peerState. nil
	// when FEC (respectively adaptive FEC) is disabled — the datapath is then byte-for-byte
	// the pre-T24 behaviour. See fec.go.
	fecCfg      *fec.Config
	adaptiveCfg *adaptivefec.Config

	// Receive fan-in (T30). To let a path be added at runtime WITHOUT the engine
	// spawning a new receive goroutine (it only builds its receive goroutines once,
	// from the ReceiveFuncs Open returns), the per-path socket reads are decoupled
	// from the engine-facing delivery: the Bind owns one readLoop goroutine PER path
	// (tracked by readersWG) that reads its socket and feeds the shared resequencer,
	// and Open returns a SINGLE engine-facing ReceiveFunc that drains the resequencer
	// in order. A reader pokes deliverSignal after each datagram so the drainer wakes;
	// recvClosed is closed by Close to release both the drainer and any reader parked
	// on a delivery. openPort mirrors Open's bind port so a runtime-added path binds
	// consistently; nextPathID is a monotonic high-water that persists ACROSS Open
	// spans (a Close->Open never lowers it; only a process restart resets it), so a
	// surviving path is never renumbered and a freed id is never reused for the
	// process lifetime, and thus can never collide with the peer's per-path reflector
	// state.
	deliverSignal chan struct{}
	recvClosed    chan struct{}
	readersWG     sync.WaitGroup
	openPort      uint16
	nextPathID    uint16

	// Receive-path liveness sweep (T39, defect D15). Liveness DOWN-detection normally
	// rides StartProbeLoop's single wall-clock ticker goroutine (emitProbes → Tick).
	// Under heavy CPU load — e.g. the concentrator absorbing a saturating forward flood
	// on 4 vCPU — that timer goroutine can be scheduled with ~1s jitter, delaying a
	// path-DOWN transition (and thus the reply-direction failover) past the P1 budget.
	// The per-path receive goroutines, in contrast, are the goroutines the inbound
	// traffic is ALREADY scheduling, so driving Tick from them re-evaluates liveness
	// even when the timer goroutine is starved. sweepIntervalNanos is the probe
	// interval (0 until StartProbeLoop arms it — a bind without the probe transport
	// never sweeps); lastSweepNanos is the wall-clock high-water throttling the sweep
	// to at most once per interval so the receive hot path stays cheap.
	sweepIntervalNanos atomic.Int64
	lastSweepNanos     atomic.Int64

	// everUp is the STICKY "ever had a live path" predicate (I4): set true the first time
	// ANY path, for ANY bound peer, reaches liveness telemetry.StateUp (dispatchInbound,
	// on a fresh probe echo), and never cleared afterward — a later total outage is a
	// genuine failure signal, not a startup warmup. The device-package engineLogger
	// adapter consults EverHadLivePath to downgrade the startup no-healthy-path spam
	// (ErrNoHealthyPath) to a single coalesced INFO line until the first path comes up,
	// then lets it log at ERROR (a real outage) from then on.
	everUp atomic.Bool
}

// compile-time proof that Multipath satisfies the engine's Bind contract.
var _ Bind = (*Multipath)(nil)

// NewMultipath returns a closed multipath Bind over the configured paths; call
// Open to bind the per-path sockets. The PSK keys the outer framing and must be
// set (config validation guarantees it). The scheduler is the injected send-side
// path-selection policy (T15) whose priority order MUST match the paths slice
// order (index 0 = the preferred primary); it is a required collaborator so the
// send path is never without a policy.
//
// probers is the per-path probe initiator that drives on-wire liveness (T13/T37).
// When non-nil it MUST hold exactly one *telemetry.Prober per path, in path order,
// and those SAME values MUST be the scheduler's PathHealth sources so the liveness
// the probe loop measures is the liveness the scheduler selects on. Pass nil to
// run the bind without the probe transport (the T12 unit tests drive selection via
// sched.AlwaysUp instead). A Reflector is built from the PSK to answer peer probes.
//
// newProber is the factory the runtime path-add path (AddPath, T30) uses to mint a
// prober for a newly-admitted path; it must be non-nil to allow AddPath and MUST be
// paired with a non-nil probers (the boot-time set) — a factory without a boot-time
// slice would let AddPath append to a nil m.probers, breaking the m.paths/m.probers
// alignment invariant and panicking on the next Open at m.probers[i]. Pass nil to
// forbid runtime path addition.
//
// fecCfg is the fixed-ratio Reed-Solomon FEC configuration (T24). Pass nil to run the
// datapath with FEC disabled (the pre-T24 behaviour, byte-for-byte); a non-nil,
// pre-validated config turns the send-side parity encoder and receive-side recovery
// decoder on. It is validated here (fail fast) so an invalid ratio is rejected at
// construction rather than at the first Open.
// adaptiveCfg is the adaptive-FEC controller configuration (T29). Pass nil for the
// fixed-ratio behaviour (T24); a non-nil config REQUIRES a non-nil fecCfg (the
// controller resizes the FEC encoder's parity — it is meaningless with the plane off)
// and reinterprets fecCfg.ParityShards as the controller's parity ceiling. It is
// validated here (fail fast) so a mis-tuned control law is rejected at construction.
//
// amnezia is the tunnel's AmneziaWG obfuscation profile (config.Amnezia). It
// parameterizes the send-path frame-type classifier so a WireGuard control frame is
// recognised and pacing-exempted under advanced security — custom magic headers and
// handshake junk prefixes — as well as in vanilla mode (defect D22). Pass the zero value
// for a vanilla (unobfuscated) tunnel; the classifier then uses the default type words
// and no junk prefix. It does NOT need to match the config's validated state — an
// all-zero profile is exactly the vanilla classifier.
func NewMultipath(paths []config.Path, psk config.Key, scheduler sched.Scheduler, probers []*telemetry.Prober, newProber ProberFactory, fecCfg *fec.Config, adaptiveCfg *adaptivefec.Config, amnezia config.Amnezia) (*Multipath, error) {
	if len(paths) == 0 {
		return nil, errors.New("bind: at least one path is required")
	}
	if !psk.IsSet() {
		return nil, errors.New("bind: PSK is required for outer framing")
	}
	if len(paths) > 256 {
		// path-id is a uint8 in the DATA frame header.
		return nil, fmt.Errorf("bind: at most 256 paths supported, got %d", len(paths))
	}
	if scheduler == nil {
		return nil, errors.New("bind: a send scheduler is required")
	}
	if newProber != nil && probers == nil {
		// A runtime-path factory without a boot-time prober slice would let AddPath append
		// to a nil m.probers, desyncing m.paths from m.probers and panicking on the next
		// Open at m.probers[i]. The two are paired by construction; enforce it here.
		return nil, errors.New("bind: newProber requires a non-nil probers (boot-time set)")
	}
	if probers != nil && len(probers) != len(paths) {
		return nil, fmt.Errorf("bind: probers must have one entry per path (got %d, want %d)", len(probers), len(paths))
	}
	for i, pr := range probers {
		if pr == nil {
			return nil, fmt.Errorf("bind: prober %d is nil", i)
		}
	}
	if fecCfg != nil {
		if err := fecCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid FEC configuration: %w", err)
		}
		if fecCfg.Deadline > maxFECDeadline {
			// A deadline this large makes every deadline-flushed group's recovery
			// structurally late: the resequencer skips the gap (resequencerTimeout) before
			// the parity-derived frames land, so recovery never delivers. Reject it rather
			// than ship a bond whose FEC silently cannot help (defect #4).
			return nil, fmt.Errorf("bind: fec deadline %s exceeds the max %s (must stay safely below the resequencer's %s per-gap timeout so deadline-flushed recovery lands before the gap is skipped)", fecCfg.Deadline, maxFECDeadline, resequencerTimeout)
		}
	}
	if adaptiveCfg != nil {
		if fecCfg == nil {
			return nil, errors.New("bind: adaptive FEC requires a FEC configuration (the controller resizes the FEC encoder's parity)")
		}
		if err := adaptiveCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid adaptive FEC configuration: %w", err)
		}
		// The controller's parity ceiling (MaxParity) is the fixed FEC ParityShards both
		// ends agree on: the receiver's decoder is built at fecCfg.ParityShards, and the
		// encoder must never emit more parity than that ceiling (SetParity clamps to it).
		// A mismatch would let the controller target a parity index the decoder rejects,
		// so bind the two together at construction rather than trusting the caller.
		if adaptiveCfg.MaxParity != fecCfg.ParityShards {
			return nil, fmt.Errorf("bind: adaptive FEC parity ceiling (MaxParity=%d) must equal the FEC parity_shards (%d), which the receiver's decoder is built at", adaptiveCfg.MaxParity, fecCfg.ParityShards)
		}
		if adaptiveCfg.DataShards != fecCfg.DataShards {
			return nil, fmt.Errorf("bind: adaptive FEC DataShards (%d) must equal the FEC data_shards (%d)", adaptiveCfg.DataShards, fecCfg.DataShards)
		}
	}
	// The single-peer edge/hub constructs EXACTLY ONE peerState (the primary). virt is
	// created here — NOT per Open — because the concentrator pins its destination once for
	// the process life and every existing test relies on the virtual-endpoint pointer being
	// stable across Open/Close/add/remove.
	primary := newPeerState("", psk, scheduler, newProber, probers)
	m := &Multipath{
		defs:              append([]config.Path(nil), paths...),
		classify:          newWGClassifier(amnezia),
		deferredListen:    defaultDeferredListen,
		resolveDeviceBind: resolveForcedDeviceBind,
		addPathListen:     listenPath,
		peerState:         primary,
		peers:             []*peerState{primary},
		peersByName:       map[string]*peerState{primary.name: primary},
		peerByEndpoint:    map[netip.AddrPort]*peerState{},
		peerByVirt:        map[*udpEndpoint]*peerState{primary.virt: primary},
		maxDemuxSources:   defaultMaxDemuxSources,
		fecCfg:            fecCfg,
		adaptiveCfg:       adaptiveCfg,
	}
	// Publish the initial (primary-only) peer view the receive drainer iterates. No
	// concurrency yet — the bind is not open — so this runs without m.mu.
	m.republishPeersLocked()
	return m, nil
}

// republishPeersLocked snapshots m.peers into the lock-free peersView the engine-facing
// receive drainer (newReceiveFunc) iterates. The caller MUST hold m.mu whenever the bind
// can be open (so the snapshot never races a concurrent m.peers append); the constructor
// is the sole exception (it runs before the Multipath is reachable by any goroutine). The
// snapshot is a fresh slice so a later append to m.peers never mutates a view the drainer
// is mid-iteration over.
func (m *Multipath) republishPeersLocked() {
	snap := make([]*peerState, len(m.peers))
	copy(snap, m.peers)
	m.peersView.Store(&snap)
}

// AddConcentratorPeer registers one ADDITIONAL bound peer with the Bind — the concentrator's
// per-peer wiring (G4/T93). Peer 0 (the embedded primary) is built by NewMultipath; the
// concentrator calls this once per additional configured peer, each with its OWN effective psk,
// send scheduler, boot-time per-path prober set, and runtime prober factory (all keyed on that
// peer's psk, so one peer's codec/reflector reject another's frames — T84/R72). The peer's
// STABLE virtual endpoint is minted here (newPeerState) and registered in peerByVirt so an
// outbound Send routes replies back to THIS peer; Open then builds this peer's per-(peer,path)
// view of every bound socket, reconciles its scheduler, and (via newReceiveFunc) reports its
// virt to the engine on the first inbound frame (invariant A1: one virtual endpoint per peer).
//
// It MUST be called BEFORE Open (while the bind is closed): the per-(peer,path) views are
// rebuilt by Open from the registered peer set on every Open span (including each Close→Open
// cycle the engine drives on Down/Up and route changes), so a peer registered after the sockets
// are bound would be view-less and its DATA/PROBE never routed. probers, when supplied, must be
// index-aligned with the configured path membership (m.defs), exactly as the primary's are.
func (m *Multipath) AddConcentratorPeer(name string, psk config.Key, scheduler sched.Scheduler, probers []*telemetry.Prober, newProber ProberFactory) error {
	if name == "" {
		return errors.New("bind: concentrator peer name is required")
	}
	if !psk.IsSet() {
		return errors.New("bind: concentrator peer psk is required")
	}
	if scheduler == nil {
		return errors.New("bind: concentrator peer requires a send scheduler")
	}
	if newProber != nil && probers == nil {
		return errors.New("bind: newProber requires a non-nil probers (boot-time set)")
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	if len(m.paths) != 0 {
		return errors.New("bind: concentrator peers must be registered before Open")
	}
	if probers != nil && len(probers) != len(m.defs) {
		return fmt.Errorf("bind: concentrator peer %q: probers must have one entry per configured path (got %d, want %d)", name, len(probers), len(m.defs))
	}
	for i, pr := range probers {
		if pr == nil {
			return fmt.Errorf("bind: concentrator peer %q: prober %d is nil", name, i)
		}
	}
	if name == m.name {
		return fmt.Errorf("bind: concentrator peer name %q collides with the primary peer", name)
	}
	if _, dup := m.peersByName[name]; dup {
		return fmt.Errorf("bind: duplicate concentrator peer name %q", name)
	}
	p := newPeerState(name, psk, scheduler, newProber, probers)
	m.peers = append(m.peers, p)
	m.peersByName[name] = p
	m.peerByVirt[p.virt] = p
	// Publish the grown peer set so the engine-facing receive drainer (newReceiveFunc) will
	// enumerate this peer's resequencer once Open builds it.
	m.republishPeersLocked()
	return nil
}

// Open binds one UDP socket per configured path to that path's source address on
// port (0 = random per socket), sets a large SO_RCVBUF on each, spawns one
// Bind-owned reader per path, and returns a SINGLE engine-facing ReceiveFunc (the
// fan-in drainer) plus the first path's bound port. Each path whose config carries
// a dest_addr — or, failing that, the peer's wireguard endpoint learned via
// ParseEndpoint — starts with a known remote; the rest are learned from inbound
// traffic.
//
// Open is the sole creator of the per-path sockets: the engine's bring-up path
// calls Close() first (on the still-unopened bind) and then Open(), so building
// the sockets HERE — not in NewMultipath — is what makes that Close→Open sequence
// (and every subsequent Down→Up) work. The engine passes the previously-bound
// port back on a re-Open; each path binds to it on its own distinct source
// address, and the first path's bound port is returned so the engine keeps a
// stable listen port across the cycle (matching conn.StdNetBind).
func (m *Multipath) Open(port uint16) ([]ReceiveFunc, uint16, error) {
	m.mu.Lock()
	defer m.mu.Unlock()
	if len(m.paths) != 0 {
		return nil, 0, conn.ErrBindAlreadyOpen
	}

	// (Re)build the per-Open datapath planes — send Codec, receive resequencer, and FEC
	// send/receive state — fresh for this bring-up, for EVERY bound peer (not just the
	// primary via promotion). This keeps Open symmetric with closeSocketsLocked, which
	// clears every peer's per-Open state: a concentrator peer bound before Open must get
	// its OWN fresh planes on each Close→Open cycle, and one peer's (re)creation must never
	// touch another peer's release point or FEC group state. On the single-peer edge/hub
	// m.peers holds only the primary, so this is byte-identical to the pre-split rebuild.
	// See openPeerDatapathLocked.
	for _, p := range m.peers {
		if err := m.openPeerDatapathLocked(p); err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, err
		}
	}

	// Resolve every path's interface up front and decide, per path, whether its
	// socket may be device-bound (SO_BINDTODEVICE + wildcard — survives a T16
	// re-roam) or must pin the specific source IP (the pre-T16 behaviour, required
	// when paths share an interface or the interface is multi-address, so distinct
	// specific-IP sockets coexist on one port without an EADDRINUSE collision). See
	// selectDeviceBinds.
	srcs := make([]netip.Addr, len(m.defs))
	modes := make([]config.BindMode, len(m.defs))
	for i := range m.defs {
		srcs[i] = m.defs[i].SourceAddr
		modes[i] = m.defs[i].Bind
	}
	bindDevs := planPathBinds(srcs, modes)

	// A path whose WELL-FORMED source_addr is merely NOT-YET-ASSIGNABLE at boot
	// (EADDRNOTAVAIL: no interface holds the address — a 5G modem without a DHCP
	// lease, Starlink mid-obstruction) is DEFERRED rather than treated as fatal, so
	// the bond comes up on the paths that DO bind (G2/W1, approach A). Tolerating it
	// requires the runtime path-down machinery: the deferred path's prober stays
	// StateDown so the scheduler excludes it, and a DynamicScheduler whose membership
	// can be reconciled to only the bound paths. Absent the probe transport (the T12
	// no-prober unit binds) or a dynamic scheduler there is no such Down model, so —
	// exactly as AddPath refuses a runtime add without probers — every bind error
	// stays fatal there. A MALFORMED source_addr never reaches here (config.validate
	// rejects it at load), and any OTHER bind error (EADDRINUSE, permission) is fatal.
	_, dynOK := m.scheduler.(sched.DynamicScheduler)
	tolerateDefer := m.probers != nil && dynOK
	m.deferred = nil

	actualPort := port
	firstBound := true
	for i := range m.defs {
		def := m.defs[i]
		// Device-bind this path when selectDeviceBinds proved it safe (so a
		// mid-session source-address change / T16 re-roam does not break the socket),
		// otherwise pin the specific source IP. See selectDeviceBinds / listenPath.
		c, err := listenPath(def.SourceAddr, port, bindDevs[i])
		if err != nil {
			if tolerateDefer && errors.Is(err, syscall.EADDRNOTAVAIL) {
				// Defer this path: record its def + boot prober (kept Down) for the T55
				// background reconcile to retry, and leave the bond to come up on the rest.
				// Mirrors AddPath's rollback discipline — a failed path never disturbs the
				// tunnel — at the boot boundary.
				m.deferred = append(m.deferred, deferredPath{def: def, prober: m.probers[i]})
				continue
			}
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: open path %q on %s: %w", def.Name, def.SourceAddr, err)
		}
		// Large SO_RCVBUF, best-effort: the kernel caps at net.core.rmem_max and
		// SetReadBuffer does not require privilege, so a returned error is rare;
		// treat it as non-fatal rather than refusing to bind in a restricted env.
		_ = c.SetReadBuffer(socketRecvBuffer)

		shared := &sharedPathState{name: def.Name, id: uint8(i), src: def.SourceAddr, conn: c}
		// Build EVERY bound peer's view of this shared socket (T93): each peer decodes under its
		// OWN psk-derived Codec and probes with its OWN per-(peer,path) prober, so a concentrator
		// socket shared by several peers keeps each peer's authenticated stream isolated
		// (demuxInbound source-demuxes on the first authenticated PROBE). The primary (peers[0])
		// is built exactly as the pre-split single peer — byte-identical on the single-peer
		// edge/hub, where m.peers holds only the primary. m.paths (the primary's path slice,
		// reached through the embed) grows via the pi==0 append below; a concentrator peer's
		// paths grow on its own peerState.
		for pi, p := range m.peers {
			// The path binds to peer p; its receive codec is p's codec (derived from p's psk).
			codec, err := p.newCodec()
			if err != nil {
				_ = c.Close()
				_ = m.closeSocketsLocked()
				return nil, 0, err
			}
			pp := &peerPathState{sharedPathState: shared, peer: p, codec: codec}
			if p.probers != nil {
				// Fail fast rather than panic if a peer's prober slice ever falls short of the
				// shared m.defs membership: every runtime admission (bound OR deferred) fans a
				// per-peer prober out to EVERY peer (AddPath), so p.probers stays index-aligned
				// with m.defs. A divergence is a wiring defect — surface it as a bind error
				// instead of an index-out-of-range panic that would crash the daemon.
				if i >= len(p.probers) {
					_ = c.Close()
					_ = m.closeSocketsLocked()
					return nil, 0, fmt.Errorf("bind: peer %q prober set (len %d) is shorter than the path membership at index %d — per-peer prober fan-out desync", p.name, len(p.probers), i)
				}
				pp.prober = p.probers[i]
				if pi == 0 {
					// Reconcile the SHARED DATA-frame path-id to the PRIMARY prober's IMMUTABLE
					// stamp rather than the slice index i: after a runtime RemovePath the survivor
					// keeps its original (higher) stamp, so index-based numbering would renumber a
					// live path AND diverge its DATA id from its PROBE stamp. Every peer's
					// probers[i] carries the SAME stamp (the device stamps each peer's boot prober
					// for path i identically), so taking it from the primary is authoritative and
					// keeps DATA and every peer's PROBE agreeing on the wire.
					shared.id = pp.prober.PathID()
				}
			}
			switch {
			case def.DestAddr.IsValid():
				pp.setRemote(def.DestAddr)
			case m.hasDefaultRemote:
				pp.setRemote(m.defaultRemote)
			}
			p.paths = append(p.paths, pp)
			// Publish this peer's view for the receive demux (T88). A single-view socket is the
			// edge/hub byte-identical fast path in demuxInbound; a socket with >1 view is
			// source-demuxed to its owning peer on each authenticated PROBE.
			shared.addViewLocked(pp)
		}
		m.shared = append(m.shared, shared)
		if firstBound {
			actualPort = uint16(c.LocalAddr().(*net.UDPAddr).Port)
			firstBound = false
		}
	}

	// Hard guard (a): a bond with NO transport is impossible. If every configured path
	// deferred, tolerance must NOT degrade to a zero-path bind — fail fatally, exactly
	// as the pre-tolerance Open did when the sole path could not bind.
	if len(m.paths) == 0 {
		_ = m.closeSocketsLocked()
		return nil, 0, fmt.Errorf("bind: no configured path could bind its source address (all %d deferred as not-yet-assignable)", len(m.deferred))
	}

	// nextPathID is a MONOTONIC HIGH-WATER carried ACROSS Open spans, never decreased.
	// Close does not reset it, and here it is only ever RAISED to at least max(existing
	// path stamp)+1. Resetting it to len(m.paths) (the pre-fix behaviour) re-minted an id
	// a survivor still held once a RemovePath had opened a gap in the stamp space below
	// that survivor's stamp: the next runtime AddPath then collided with the live path at
	// an identical (PathID, SessionID), and because the peer's Reflector keys anti-replay
	// AND the session challenge PER PathID, the strict-monotonic replay filter dropped one
	// of the two independent ProbeSeq streams -> probe loss / false-DOWN. Deriving the
	// high-water from the (prober-stamped) ps.id covers both the probe-transport case and
	// the T12 no-prober case (where ps.id == i, so the high-water is len(m.paths)).
	m.openPort = port
	for _, ps := range m.paths {
		if uint16(ps.id)+1 > m.nextPathID {
			m.nextPathID = uint16(ps.id) + 1
		}
	}
	// A DEFERRED path's boot prober already OWNS its path-id stamp; raise the
	// high-water past it too, so a runtime AddPath arriving while the path is still
	// deferred cannot mint that reserved id and collide with it once T55 binds it.
	for _, dp := range m.deferred {
		if dp.prober != nil {
			if uint16(dp.prober.PathID())+1 > m.nextPathID {
				m.nextPathID = uint16(dp.prober.PathID()) + 1
			}
		}
	}

	// Reconcile the scheduler's membership with the path slice just rebuilt from
	// m.defs. A runtime AddPath/RemovePath (T30) keeps m.defs, m.probers, AND the
	// live scheduler in lockstep during an Open span; re-pinning the scheduler's
	// health list to the BOUND probers HERE — index-aligned with m.paths, since each
	// bound path appended its ps.prober to boundProbers in order above — is the single
	// reconciliation point that makes that runtime membership survive this
	// Close→Open cycle without a scheduler/path desync (no frozen zombie health
	// entry, no resurrected removed path). A DEFERRED path (not-yet-assignable
	// source_addr) is deliberately EXCLUDED here: its prober is absent from the
	// scheduler, so Pick can never select it, and Send's Pick->m.paths[idx] mapping
	// stays index-aligned with the bound-only path slice. Only meaningful with the
	// probe transport: a bind without probers cannot change membership at runtime
	// (AddPath is refused) and never defers, so its scheduler is left exactly as built.
	// Reconcile EACH bound peer's scheduler membership with the path slice just rebuilt from
	// m.defs (T93): every peer's per-(peer,path) views were appended in m.defs order above, so a
	// peer's scheduler health list is that peer's BOUND probers in order (a DEFERRED path
	// contributed no view and is deliberately excluded, exactly as for the primary). On the
	// single-peer edge/hub m.peers holds only the primary, so this reconciles exactly the one
	// scheduler — byte-identical to the pre-split single reconcile. A peer without the probe
	// transport or with a non-dynamic scheduler is left as built (the T12 no-prober unit binds
	// never change membership at runtime and never defer).
	for _, p := range m.peers {
		pdyn, pdynOK := p.scheduler.(sched.DynamicScheduler)
		if p.probers == nil || !pdynOK {
			continue
		}
		health := make([]sched.PathHealth, 0, len(p.paths))
		for _, pp := range p.paths {
			if pp.prober != nil {
				health = append(health, pp.prober)
			}
		}
		if err := pdyn.SetPaths(health); err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: reconcile scheduler on open: %w", err)
		}
	}

	// Stand up the receive fan-in: one Bind-owned reader per path feeding the shared
	// resequencer, and a single engine-facing drainer. Both channels are recreated
	// per Open so a Close→Open cycle starts clean.
	m.deliverSignal = make(chan struct{}, 1)
	m.recvClosed = make(chan struct{})
	for _, ps := range m.paths {
		m.readersWG.Add(1)
		go m.readLoop(ps, m.deliverSignal)
	}
	// Deadline-tick goroutine for FEC group close (T24): it flushes a partial group's
	// parity on time under low load so a group is never stranded waiting for the size
	// threshold. Tracked by readersWG (like the readers) so Close waits for it; it
	// exits on recvClosed. It TryLocks m.mu, so it never blocks Close's readersWG.Wait
	// held under m.mu.
	if m.fecSend.Load() != nil {
		m.readersWG.Add(1)
		go m.fecTickLoop(m.fecCfg.Deadline, m.recvClosed)
	}
	return []ReceiveFunc{m.newReceiveFunc(m.deliverSignal, m.recvClosed)}, actualPort, nil
}

// openPeerDatapathLocked (re)builds ONE peer's per-Open datapath planes: its send Codec
// (derived from THIS peer's psk), its receive resequencer, and — when FEC is configured —
// its FEC send/receive planes. Each is fresh per Open so a Close→Open cycle (or reconnect)
// re-pins the peer's release point and re-anchors its FEC grouping to this bring-up rather
// than a stale prior span. It writes ONLY the given peer's fields (from the peer's own psk
// and the bind-wide fecCfg/adaptiveCfg), so one peer's (re)creation never touches another
// peer's resequencer or FEC group state — the per-peer lifecycle boundary that keeps a
// reconnect on one peer from disturbing another's. Caller holds m.mu; on error the caller
// unwinds the whole Open via closeSocketsLocked (which clears every peer's per-Open state),
// so a partial build here is cleaned up.
func (m *Multipath) openPeerDatapathLocked(ps *peerState) error {
	sendCodec, err := ps.newCodec()
	if err != nil {
		return err
	}

	// A fresh resequencer per Open: its release point re-pins to the first frame THIS peer
	// receives after this bring-up, so a Close→Open cycle (or reconnect) never wedges on a
	// stale high-water outer-seq. Published atomically so the peer's per-path readLoop
	// goroutines read it WITHOUT m.mu.
	ps.resequencer.Store(reseq.New(resequencerWindow, resequencerTimeout, reseq.SystemClock{}))

	// Fresh FEC send/receive state per Open, when FEC is enabled (T24). The encoder
	// group state and the decoder's per-group buffers re-pin with the sockets, so a
	// Close→Open cycle never reconstructs against a stale group. Both are torn down (per
	// peer) in closeSocketsLocked. A build error here is a programmer error (the ratio was
	// validated in NewMultipath), so it fails the Open.
	if m.fecCfg != nil {
		fs, err := m.newFECSender()
		if err != nil {
			return err
		}
		ps.fecSend.Store(fs)
		fr, err := m.newFECReceiver()
		if err != nil {
			return err
		}
		ps.fecRecv.Store(fr)
	}
	ps.sendCodec = sendCodec
	return nil
}

// newFECSender builds a fresh FEC send plane (group encoder + optional adaptive controller)
// from the bind-wide fecCfg/adaptiveCfg, or returns (nil, nil) when FEC is disabled. Like
// newFECReceiver it reads only immutable post-construction config, so it is safe to call
// WITHOUT m.mu — which the lock-free re-instantiation on re-bind (ensurePeerReceiveInstantiated)
// relies on to rebuild a torn-down concentrator peer's send plane symmetric to the receive
// plane. Open calls it too, so a lazily-rebuilt fecSend is byte-identical to an eagerly-opened
// one: a fresh encoder re-pinned to this bring-up, and in adaptive mode a fresh controller
// starting the control law from M=0 (no standing redundancy until loss is observed). A build
// error is a programmer error (the ratio/controller cfg were validated in NewMultipath).
func (m *Multipath) newFECSender() (*fecSender, error) {
	if m.fecCfg == nil {
		return nil, nil
	}
	enc, err := fec.NewEncoder(*m.fecCfg, fec.SystemClock{})
	if err != nil {
		return nil, fmt.Errorf("bind: build FEC encoder: %w", err)
	}
	fs := &fecSender{enc: enc}
	if m.adaptiveCfg != nil {
		ctrl, err := adaptivefec.NewController(*m.adaptiveCfg, adaptivefec.SystemClock{})
		if err != nil {
			return nil, fmt.Errorf("bind: build adaptive FEC controller: %w", err)
		}
		fs.ctrl = ctrl
		// Adopt the controller's starting parity so encoder and controller agree from t=0; the
		// tick loop sizes it to measured loss within the first control interval. Fixed mode
		// leaves the encoder at its cfg.ParityShards default instead.
		enc.SetParity(ctrl.Parity())

